private extension UIView {
    func findEnclosingScrollView() -> UIScrollView? {
        var current: UIView? = superview
        while let view = current {
            if let sv = view as? UIScrollView, sv !== self {
                return sv
            }
            current = view.superview
        }
        return nil
    }
}

