struct DiscoverFullScreenSearchInputView: View {
    @Environment(\.dismiss) private var dismiss

    let title: String
    let placeholder: String
    let initialQuery: String
    let onSearch: (String) -> Void

    @State private var query: String
    @FocusState private var isInputFocused: Bool

    init(
        title: String,
        placeholder: String,
        initialQuery: String = "",
        onSearch: @escaping (String) -> Void
    ) {
        self.title = title
        self.placeholder = placeholder
        self.initialQuery = initialQuery
        self.onSearch = onSearch
        _query = State(initialValue: initialQuery)
    }

    var body: some View {
        VStack(spacing: 18) {
            VStack(alignment: .leading, spacing: 8) {
                HStack(spacing: 8) {
                    Image(systemName: "sparkles")
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(RaverTheme.accent)
                    Text(L("探索模式", "Explore Mode"))
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(RaverTheme.secondaryText)
                }

                Text(title)
                    .font(.title3.weight(.bold))
                    .foregroundStyle(RaverTheme.primaryText)
                    .lineLimit(2)
                    .minimumScaleFactor(0.8)

                Text(L("输入关键词开始搜索，结果会从右侧继续推进。", "Enter keywords and the results page will slide in from the right."))
                    .font(.caption)
                    .foregroundStyle(RaverTheme.secondaryText)
                    .lineLimit(2)
                    .minimumScaleFactor(0.85)
            }
            .frame(maxWidth: .infinity, alignment: .leading)

            VStack(spacing: 10) {
                HStack(spacing: 8) {
                    Image(systemName: "magnifyingglass")
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(RaverTheme.secondaryText)

                    TextField(placeholder, text: $query)
                        .font(.headline)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled(true)
                        .focused($isInputFocused)
                        .onSubmit {
                            submit()
                        }
                }
                .padding(.horizontal, 14)
                .frame(height: 50)
                .background(RaverTheme.card, in: RoundedRectangle(cornerRadius: 14, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .strokeBorder(RaverTheme.secondaryText.opacity(0.18), lineWidth: 1)
                )

                Button {
                    submit()
                } label: {
                    HStack(spacing: 8) {
                        Image(systemName: "arrow.right")
                            .font(.subheadline.weight(.bold))
                        Text(L("查看结果", "View Results"))
                            .font(.subheadline.weight(.semibold))
                    }
                    .foregroundStyle(.white)
                    .frame(maxWidth: .infinity)
                    .frame(height: 44)
                    .background(
                        LinearGradient(
                            colors: [
                                RaverTheme.accent.opacity(trimmedQuery.isEmpty ? 0.42 : 1),
                                Color(red: 0.33, green: 0.22, blue: 0.88).opacity(trimmedQuery.isEmpty ? 0.35 : 0.92)
                            ],
                            startPoint: .leading,
                            endPoint: .trailing
                        ),
                        in: RoundedRectangle(cornerRadius: 12, style: .continuous)
                    )
                }
                .buttonStyle(.plain)
                .disabled(trimmedQuery.isEmpty)
            }
            .padding(12)
            .background(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .fill(RaverTheme.card.opacity(0.42))
            )
            .overlay(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .strokeBorder(RaverTheme.secondaryText.opacity(0.12), lineWidth: 1)
            )

            Spacer(minLength: 0)
        }
        .padding(.horizontal, 16)
        .padding(.top, 10)
        .background(RaverTheme.background)
        .navigationBarTitleDisplayMode(.inline)
        .toolbar(.hidden, for: .tabBar)
        .toolbar {
            ToolbarItem(placement: .topBarLeading) {
                Button(L("取消", "Cancel")) {
                    dismiss()
                }
            }
            ToolbarItemGroup(placement: .keyboard) {
                Spacer()
                Button(L("收起", "Dismiss")) {
                    isInputFocused = false
                }
            }
        }
        .onAppear {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.05) {
                isInputFocused = true
            }
        }
    }

    private var trimmedQuery: String {
        query.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func submit() {
        let keyword = trimmedQuery
        guard !keyword.isEmpty else { return }
        isInputFocused = false
        onSearch(keyword)
    }
}

