struct DJsSearchResultsView: View {
    private let service = AppEnvironment.makeWebService()
    let query: String

    @State private var djs: [WebDJ] = []
    @State private var rankingBoards: [RankingBoard] = []
    @State private var isLoading = false
    @State private var selectedDJForDetail: WebDJ?
    @State private var selectedBoardForDetail: RankingBoard?
    @State private var errorMessage: String?

    var body: some View {
        VStack(spacing: 10) {
            DiscoverSearchResultHeader(
                title: L("DJ / 榜单结果", "DJ / Ranking Results"),
                query: query,
                resultCount: {
                    let total = djs.count + rankingBoards.count
                    return total == 0 ? nil : total
                }()
            )

            Group {
                if isLoading && djs.isEmpty && rankingBoards.isEmpty {
                    ProgressView(L("搜索中...", "Searching..."))
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                } else if djs.isEmpty && rankingBoards.isEmpty {
                    ContentUnavailableView(
                        L("未找到 DJ 或榜单", "No DJs or rankings found"),
                        systemImage: "music.mic",
                        description: Text(L("关键词：\(query)", "Keyword: \(query)"))
                    )
                } else {
                    ScrollView {
                        VStack(alignment: .leading, spacing: 16) {
                            if !djs.isEmpty {
                                VStack(alignment: .leading, spacing: 10) {
                                    Text(L("DJ", "DJ"))
                                        .font(.headline.weight(.bold))
                                        .foregroundStyle(RaverTheme.primaryText)

                                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                                        ForEach(djs) { dj in
                                            Button {
                                                selectedDJForDetail = dj
                                            } label: {
                                                DJSearchResultCard(dj: dj)
                                            }
                                            .buttonStyle(.plain)
                                        }
                                    }
                                }
                            }

                            if !rankingBoards.isEmpty {
                                VStack(alignment: .leading, spacing: 10) {
                                    Text(L("榜单", "Rankings"))
                                        .font(.headline.weight(.bold))
                                        .foregroundStyle(RaverTheme.primaryText)

                                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                                        ForEach(rankingBoards) { board in
                                            Button {
                                                selectedBoardForDetail = board
                                            } label: {
                                                RankingBoardCoverCard(board: board)
                                            }
                                            .buttonStyle(.plain)
                                            .frame(maxWidth: .infinity)
                                            .frame(height: 254)
                                            .clipped()
                                            .contentShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                                        }
                                    }
                                }
                            }
                        }
                        .padding(.horizontal, 2)
                        .padding(.top, 4)
                        .padding(.bottom, 16)
                    }
                }
            }
        }
        .padding(.horizontal, 14)
        .padding(.top, 8)
        .background(RaverTheme.background)
        .navigationTitle(L("搜索", "Search"))
        .navigationBarTitleDisplayMode(.inline)
        .toolbar(.hidden, for: .tabBar)
        .task {
            await load()
        }
        .refreshable {
            await load()
        }
        .fullScreenCover(item: $selectedDJForDetail) { dj in
            DiscoverCoordinatorView {
                DJDetailView(djID: dj.id)
            }
        }
        .navigationDestination(item: $selectedBoardForDetail) { board in
            RankingBoardDetailView(board: board)
        }
        .alert(L("提示", "Notice"), isPresented: Binding(
            get: { errorMessage != nil },
            set: { if !$0 { errorMessage = nil } }
        )) {
            Button(L("确定", "OK"), role: .cancel) {}
        } message: {
            Text(errorMessage ?? "")
        }
    }

    @MainActor
    private func load() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            async let djPage = service.fetchDJs(page: 1, limit: 100, search: query, sortBy: "followerCount")
            async let boardList = service.fetchRankingBoards()
            djs = try await djPage.items
            let allBoards = try await boardList
            let keyword = query.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            rankingBoards = allBoards.filter { board in
                board.title.lowercased().contains(keyword)
                    || (board.subtitle?.lowercased().contains(keyword) ?? false)
            }
        } catch {
            errorMessage = error.userFacingMessage
        }
    }
}

struct SetsSearchResultsView: View {
    private let service = AppEnvironment.makeWebService()
    private let columns = [
        GridItem(.flexible(), spacing: 12),
        GridItem(.flexible(), spacing: 12),
    ]

    let query: String

    @State private var sets: [WebDJSet] = []
    @State private var isLoading = false
    @State private var selectedSetForPlayback: WebDJSet?
    @State private var errorMessage: String?

    var body: some View {
        VStack(spacing: 10) {
            DiscoverSearchResultHeader(
                title: L("Sets 搜索结果", "Sets Search Results"),
                query: query,
                resultCount: sets.isEmpty ? nil : sets.count
            )

            Group {
                if isLoading && sets.isEmpty {
                    ProgressView(L("搜索中...", "Searching..."))
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                } else if sets.isEmpty {
                    ContentUnavailableView(
                        L("未找到 Sets", "No sets found"),
                        systemImage: "waveform.path.ecg",
                        description: Text(L("关键词：\(query)", "Keyword: \(query)"))
                    )
                } else {
                    ScrollView {
                        LazyVGrid(columns: columns, spacing: 14) {
                            ForEach(sets) { set in
                                Button {
                                    selectedSetForPlayback = set
                                } label: {
                                    DJSetGridCard(set: set)
                                }
                                .buttonStyle(.plain)
                            }
                        }
                        .padding(.horizontal, 2)
                        .padding(.top, 4)
                        .padding(.bottom, 16)
                    }
                }
            }
        }
        .padding(.horizontal, 14)
        .padding(.top, 8)
        .background(RaverTheme.background)
        .navigationTitle(L("搜索", "Search"))
        .navigationBarTitleDisplayMode(.inline)
        .toolbar(.hidden, for: .tabBar)
        .task {
            await load()
        }
        .refreshable {
            await load()
        }
        .fullScreenCover(item: $selectedSetForPlayback) { set in
            NavigationStack {
                DJSetDetailView(setID: set.id)
            }
            .toolbar(.hidden, for: .tabBar)
        }
        .alert(L("提示", "Notice"), isPresented: Binding(
            get: { errorMessage != nil },
            set: { if !$0 { errorMessage = nil } }
        )) {
            Button(L("确定", "OK"), role: .cancel) {}
        } message: {
            Text(errorMessage ?? "")
        }
    }

    @MainActor
    private func load() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            var pool: [WebDJSet] = []
            var currentPage = 1
            var totalPages = 1
            repeat {
                let page = try await service.fetchDJSets(page: currentPage, limit: 20, sortBy: "latest", djID: nil)
                pool.append(contentsOf: page.items)
                totalPages = page.pagination?.totalPages ?? 1
                currentPage += 1
            } while currentPage <= totalPages && currentPage <= 4

            let keyword = query.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            sets = pool.filter { item in
                item.title.lowercased().contains(keyword)
                    || (item.dj?.name.lowercased().contains(keyword) ?? false)
                    || item.djId.lowercased().contains(keyword)
            }
        } catch {
            errorMessage = error.userFacingMessage
        }
    }
}

struct WikiSearchResultsView: View {
    private let service = AppEnvironment.makeWebService()
    let query: String
    let preferredSection: LearnModuleSection

    @State private var selectedTab: Tab = .labels
    @State private var labels: [LearnLabel] = []
    @State private var festivals: [LearnFestival] = []
    @State private var isLoading = false
    @State private var selectedLabelForDetail: LearnLabel?
    @State private var selectedFestivalForDetail: LearnFestival?
    @State private var errorMessage: String?

    private enum Tab: String, CaseIterable, Identifiable {
        case labels
        case festivals

        var id: String { rawValue }
        var title: String {
            switch self {
            case .labels: return L("厂牌", "Labels")
            case .festivals: return L("电音节", "Festivals")
            }
        }
    }

    init(query: String, preferredSection: LearnModuleSection) {
        self.query = query
        self.preferredSection = preferredSection
        _selectedTab = State(initialValue: preferredSection == .festivals ? .festivals : .labels)
    }

    var body: some View {
        VStack(spacing: 10) {
            DiscoverSearchResultHeader(
                title: L("Wiki 搜索结果", "Wiki Search Results"),
                query: query,
                resultCount: {
                    let total = selectedTab == .labels ? labels.count : festivals.count
                    return total == 0 ? nil : total
                }()
            )

            Picker("", selection: $selectedTab) {
                ForEach(Tab.allCases) { tab in
                    Text(tab.title).tag(tab)
                }
            }
            .pickerStyle(.segmented)
            .padding(.horizontal, 2)

            Group {
                if isLoading && labels.isEmpty && festivals.isEmpty {
                    ProgressView(L("搜索中...", "Searching..."))
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                } else if selectedTab == .labels {
                    labelsSection
                } else {
                    festivalsSection
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .padding(.horizontal, 14)
        .padding(.top, 8)
        .background(RaverTheme.background)
        .navigationTitle(L("搜索", "Search"))
        .navigationBarTitleDisplayMode(.inline)
        .toolbar(.hidden, for: .tabBar)
        .task {
            await load()
        }
        .refreshable {
            await load()
        }
        .fullScreenCover(item: $selectedLabelForDetail) { label in
            NavigationStack {
                LearnLabelDetailView(label: label)
            }
        }
        .fullScreenCover(item: $selectedFestivalForDetail) { festival in
            DiscoverCoordinatorView {
                LearnFestivalDetailView(festival: festival)
            }
        }
        .alert(L("提示", "Notice"), isPresented: Binding(
            get: { errorMessage != nil },
            set: { if !$0 { errorMessage = nil } }
        )) {
            Button(L("确定", "OK"), role: .cancel) {}
        } message: {
            Text(errorMessage ?? "")
        }
    }

    @ViewBuilder
    private var labelsSection: some View {
        if labels.isEmpty {
            ContentUnavailableView(
                L("未找到厂牌", "No labels found"),
                systemImage: "building.2",
                description: Text(L("关键词：\(query)", "Keyword: \(query)"))
            )
        } else {
            ScrollView {
                LazyVStack(spacing: 14) {
                    ForEach(labels) { label in
                        LearnLabelCard(label: label)
                            .contentShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                            .onTapGesture {
                                selectedLabelForDetail = label
                            }
                    }
                }
                .padding(.horizontal, 16)
                .padding(.vertical, 12)
            }
        }
    }

    @ViewBuilder
    private var festivalsSection: some View {
        if festivals.isEmpty {
            ContentUnavailableView(
                L("未找到电音节", "No festivals found"),
                systemImage: "music.quarternote.3",
                description: Text(L("关键词：\(query)", "Keyword: \(query)"))
            )
        } else {
            ScrollView {
                LazyVStack(spacing: 14) {
                    ForEach(festivals) { festival in
                        LearnFestivalCard(festival: festival)
                            .contentShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
                            .onTapGesture {
                                selectedFestivalForDetail = festival
                            }
                    }
                }
                .padding(.horizontal, 16)
                .padding(.vertical, 12)
            }
        }
    }

    @MainActor
    private func load() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            async let labelPage = service.fetchLearnLabels(
                page: 1,
                limit: 500,
                sortBy: LearnLabelSortOption.soundcloudFollowers.apiValue,
                order: LearnLabelSortOrder.desc.rawValue,
                search: query,
                nation: nil,
                genre: nil
            )
            async let festivalList = service.fetchLearnFestivals(search: query)

            labels = try await labelPage.items
            festivals = try await festivalList.map { LearnFestival(web: $0) }
        } catch {
            errorMessage = error.userFacingMessage
        }
    }
}

private struct EventCountryFilterSheet: View {
    @Environment(\.dismiss) private var dismiss

    @Binding var selectedAreaBuckets: Set<EventsModuleView.CountryAreaBucket>
    @Binding var selectedContinentBuckets: Set<EventsModuleView.ContinentBucket>
    @Binding var selectedCountries: Set<String>
    let availableContinents: [EventsModuleView.ContinentBucket]
    let availableCountries: [String]

    private var hasSelection: Bool {
        !selectedAreaBuckets.isEmpty || !selectedContinentBuckets.isEmpty || !selectedCountries.isEmpty
    }

    private let chipColumns = [
        GridItem(.adaptive(minimum: 88), spacing: 8, alignment: .leading)
    ]

    var body: some View {
        NavigationStack {
            VStack(spacing: 12) {
                ScrollView {
                    VStack(alignment: .leading, spacing: 14) {
                        chipSection(title: L("国家范围", "Area")) {
                            LazyVGrid(columns: chipColumns, alignment: .leading, spacing: 8) {
                                ForEach(EventsModuleView.CountryAreaBucket.allCases) { bucket in
                                    filterChip(
                                        title: bucket.title,
                                        isSelected: selectedAreaBuckets.contains(bucket)
                                    ) {
                                        toggle(bucket, in: &selectedAreaBuckets)
                                    }
                                }
                            }
                        }

                        chipSection(title: L("大洲", "Continent")) {
                            if availableContinents.isEmpty {
                                Text(L("暂无可筛选大洲", "No continent options"))
                                    .font(.caption)
                                    .foregroundStyle(RaverTheme.secondaryText)
                            } else {
                                LazyVGrid(columns: chipColumns, alignment: .leading, spacing: 8) {
                                    ForEach(availableContinents) { continent in
                                        filterChip(
                                            title: continent.title,
                                            isSelected: selectedContinentBuckets.contains(continent)
                                        ) {
                                            toggle(continent, in: &selectedContinentBuckets)
                                        }
                                    }
                                }
                            }
                        }

                        chipSection(title: L("国家", "Country")) {
                            if availableCountries.isEmpty {
                                Text(L("暂无可筛选国家", "No country options"))
                                    .font(.caption)
                                    .foregroundStyle(RaverTheme.secondaryText)
                            } else {
                                LazyVGrid(columns: chipColumns, alignment: .leading, spacing: 8) {
                                    ForEach(availableCountries, id: \.self) { country in
                                        filterChip(
                                            title: country,
                                            isSelected: selectedCountries.contains(country)
                                        ) {
                                            toggle(country, in: &selectedCountries)
                                        }
                                    }
                                }
                            }
                        }
                    }
                    .padding(.horizontal, 14)
                    .padding(.top, 10)
                    .padding(.bottom, 4)
                }

                HStack(spacing: 10) {
                    if hasSelection {
                        Button {
                            selectedAreaBuckets.removeAll()
                            selectedContinentBuckets.removeAll()
                            selectedCountries.removeAll()
                        } label: {
                            Text(L("重置", "Reset"))
                                .font(.subheadline.weight(.semibold))
                                .foregroundStyle(RaverTheme.secondaryText)
                                .frame(maxWidth: .infinity)
                                .frame(height: 42)
                                .background(RaverTheme.card, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
                                .contentShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                        }
                        .buttonStyle(.plain)
                    }

                    Button {
                        dismiss()
                    } label: {
                        Text(L("完成", "Done"))
                            .font(.subheadline.weight(.semibold))
                            .foregroundStyle(Color.white)
                            .frame(maxWidth: .infinity)
                            .frame(height: 42)
                            .background(RaverTheme.accent, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
                            .contentShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                    }
                    .buttonStyle(.plain)
                }
                .padding(.horizontal, 14)
                .padding(.bottom, 10)
            }
            .background(RaverTheme.background)
            .navigationTitle(L("筛选活动", "Filter Events"))
            .navigationBarTitleDisplayMode(.inline)
        }
    }

    private func chipSection<Content: View>(title: String, @ViewBuilder content: () -> Content) -> some View {
        VStack(alignment: .leading, spacing: 9) {
            Text(title)
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(RaverTheme.primaryText)
            content()
        }
        .padding(12)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(RaverTheme.card, in: RoundedRectangle(cornerRadius: 14, style: .continuous))
    }

    private func filterChip(title: String, isSelected: Bool, action: @escaping () -> Void) -> some View {
        Button(action: action) {
            HStack(spacing: 6) {
                Text(title)
                    .font(.caption.weight(.semibold))
                    .lineLimit(1)
                    .minimumScaleFactor(0.75)
                if isSelected {
                    Image(systemName: "checkmark")
                        .font(.caption2.weight(.bold))
                }
            }
            .foregroundStyle(isSelected ? Color.white : RaverTheme.secondaryText)
            .padding(.horizontal, 10)
            .padding(.vertical, 8)
            .frame(maxWidth: .infinity, alignment: .center)
            .background(
                Capsule()
                    .fill(isSelected ? RaverTheme.accent : RaverTheme.background.opacity(0.9))
            )
            .overlay(
                Capsule()
                    .strokeBorder(isSelected ? RaverTheme.accent : RaverTheme.secondaryText.opacity(0.18), lineWidth: 1)
            )
        }
        .buttonStyle(.plain)
    }

    private func toggle<T: Hashable>(_ value: T, in set: inout Set<T>) {
        if set.contains(value) {
            set.remove(value)
        } else {
            set.insert(value)
        }
    }
}

struct RecommendEventsModuleView: View {
    @EnvironmentObject private var appState: AppState
    @Environment(\.discoverPush) private var discoverPush
    private let service = AppEnvironment.makeWebService()
    private let cardCornerRadius: CGFloat = 28
    private static var didRegisterAlteHaasFont = false
    private static var didLogRecommendFontDiagnostics = false

    @State private var events: [WebEvent] = []
    @State private var isLoading = false
    @State private var errorMessage: String?
    @State private var markedCheckinIDsByEventID: [String: String] = [:]
    @State private var scrollPositionID: String?
    @State private var isLoopJumping = false

    private struct RecommendationLoopItem: Identifiable {
        let id: String
        let event: WebEvent
        let eventIndex: Int
        let replicaIndex: Int
    }

    private let loopReplicaCount = 31
    private var loopCenterReplica: Int { loopReplicaCount / 2 }

    var body: some View {
        Group {
                if isLoading && events.isEmpty {
                    ProgressView(L("正在生成推荐...", "Generating recommendations..."))
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                } else if events.isEmpty {
                    ContentUnavailableView(
                        L("暂无可推荐活动", "No Recommended Events"),
                        systemImage: "sparkles.tv"
                    )
                } else {
                    recommendationPager
                }
            }
            .background(RaverTheme.background)
            .navigationTitle("")
            .navigationBarTitleDisplayMode(.inline)
            .task {
                ensureRecommendFontRegistered()
                logRecommendFontDiagnosticsIfNeeded()
                await reload()
            }
            .refreshable {
                await reload()
            }
            .alert(L("提示", "Notice"), isPresented: Binding(
                get: { errorMessage != nil },
                set: { if !$0 { errorMessage = nil } }
            )) {
                Button(L("确定", "OK"), role: .cancel) {}
            } message: {
                Text(errorMessage ?? "")
            }
    }

    private var recommendationPager: some View {
        ScrollView(.vertical) {
            LazyVStack(spacing: 0) {
                ForEach(loopItems) { item in
                    recommendationCard(item.event, index: item.eventIndex)
                        .id(item.id)
                        .containerRelativeFrame(.vertical)
                        .scrollTransition(axis: .vertical) { content, phase in
                            content
                                .scaleEffect(phase.isIdentity ? 1 : 0.93)
                                .opacity(phase.isIdentity ? 1 : 0.66)
                                .blur(radius: phase.isIdentity ? 0 : 2.4)
                                .rotation3DEffect(
                                    .degrees(phase.isIdentity ? 0 : 5.5),
                                    axis: (x: 1, y: 0, z: 0),
                                    perspective: 0.72
                                )
                                .saturation(phase.isIdentity ? 1.05 : 0.86)
                        }
                }
            }
            .scrollTargetLayout()
        }
        .scrollIndicators(.hidden)
        .scrollTargetBehavior(.paging)
        .scrollPosition(id: $scrollPositionID)
        .overlay(alignment: .trailing) {
            pageIndicator
                .padding(.trailing, 10)
        }
        .onAppear {
            if scrollPositionID == nil {
                scrollPositionID = centerPageID(for: 0)
            }
        }
        .onChange(of: events) { _, newValue in
            let validIDs = Set(loopItems.map(\.id))
            if let current = scrollPositionID, validIDs.contains(current) {
                return
            }
            scrollPositionID = centerPageID(for: 0)
        }
        .onChange(of: scrollPositionID) { _, newValue in
            guard events.count > 1, let newValue, !isLoopJumping,
                  let item = loopItemByID[newValue] else { return }
            let distanceToCenter = abs(item.replicaIndex - loopCenterReplica)
            if distanceToCenter >= 3 {
                jumpToLoopTarget(centerPageID(for: item.eventIndex))
            }
        }
    }

    private var pageIndicator: some View {
        let current = currentIndex
        return VStack(spacing: 6) {
            ForEach(events.indices, id: \.self) { idx in
                Capsule()
                    .fill(idx == current ? Color.white.opacity(0.92) : Color.white.opacity(0.28))
                    .frame(width: idx == current ? 4 : 3, height: idx == current ? 22 : 10)
            }
        }
    }

    private var currentIndex: Int {
        guard let id = scrollPositionID else { return 0 }
        return loopItemByID[id]?.eventIndex ?? 0
    }

    private var loopItems: [RecommendationLoopItem] {
        guard !events.isEmpty else { return [] }
        var items: [RecommendationLoopItem] = []
        for replica in 0..<loopReplicaCount {
            for (index, event) in events.enumerated() {
                items.append(
                    RecommendationLoopItem(
                        id: loopID(replica: replica, event: event, eventIndex: index),
                        event: event,
                        eventIndex: index,
                        replicaIndex: replica
                    )
                )
            }
        }
        return items
    }

    private var loopItemByID: [String: RecommendationLoopItem] {
        Dictionary(uniqueKeysWithValues: loopItems.map { ($0.id, $0) })
    }

    private func loopID(replica: Int, event: WebEvent, eventIndex: Int) -> String {
        "loop-\(replica)-\(eventIndex)-\(event.id)"
    }

    private func centerPageID(for eventIndex: Int) -> String? {
        guard events.indices.contains(eventIndex) else { return nil }
        return loopID(replica: loopCenterReplica, event: events[eventIndex], eventIndex: eventIndex)
    }

    private func jumpToLoopTarget(_ target: String?) {
        guard let target else { return }
        isLoopJumping = true
        Task { @MainActor in
            // Wait for paging settle, then do an instant, non-animated re-anchor.
            try? await Task.sleep(nanoseconds: 140_000_000)
            var tx = Transaction()
            tx.disablesAnimations = true
            withTransaction(tx) {
                scrollPositionID = target
            }
            try? await Task.sleep(nanoseconds: 80_000_000)
            isLoopJumping = false
        }
    }

    private func recommendationCard(_ event: WebEvent, index: Int) -> some View {
        GeometryReader { proxy in
            let cardWidth = max(0, proxy.size.width - 20)
            let cardHeight = max(0, proxy.size.height - 20)
            let cardShape = RoundedRectangle(cornerRadius: cardCornerRadius, style: .continuous)

            Button {
                discoverPush(.eventDetail(eventID: event.id))
            } label: {
                ZStack {
                    // 先把图片限制在卡片框中并裁剪，后续文字层再覆盖其上。
                    recommendationCover(for: event)
                        .overlay(recommendationAtmosphereOverlay)
                        .frame(width: cardWidth, height: cardHeight)
                        .clipShape(cardShape)

                    VStack(alignment: .leading, spacing: 0) {
                        Spacer(minLength: 0)

                        VStack(alignment: .leading, spacing: 1) {
                            HStack(spacing: 8) {
                                recommendationPill(
                                    title: EventTypeOption.displayText(for: event.eventType),
                                    background: Color.white.opacity(0.15)
                                )

                                let visualStatus = EventVisualStatus.resolve(event: event)
                                recommendationPill(
                                    title: visualStatus.title,
                                    background: visualStatus.badgeBackground
                                )
                            }

                            HStack(spacing: 6) {
                                Image(systemName: "mappin.and.ellipse")
                                    .font(.system(size: 13, weight: .medium))
                                Text(recommendationLocationText(for: event))
                                    .lineLimit(2)
                                    .minimumScaleFactor(0.62)
                                    .fixedSize(horizontal: false, vertical: true)
                            }
                            .font(recommendMetaFont(size: 15, text: recommendationLocationText(for: event)))
                            .foregroundStyle(Color.white.opacity(0.88))
                            .padding(.bottom, 0)

                            HStack(spacing: 6) {
                                Image(systemName: "calendar")
                                    .font(.system(size: 12, weight: .medium))
                                Text(recommendationDateText(for: event))
                                    .lineLimit(1)
                                    .minimumScaleFactor(0.72)
                            }
                            .font(recommendMetaFont(size: 14, text: recommendationDateText(for: event)))
                            .foregroundStyle(Color.white.opacity(0.86))
                            .padding(.bottom, 1)

                            recommendationHeadline(event.name)
                        }
                        .layoutPriority(2)
                        .padding(.horizontal, 20)
                        .padding(.bottom, 28)
                    }
                    .frame(width: cardWidth, height: cardHeight, alignment: .topLeading)
                }
                .frame(width: cardWidth, height: cardHeight, alignment: .center)
                .contentShape(cardShape)
                .overlay(
                    cardShape
                        .stroke(Color.white.opacity(0.10), lineWidth: 1)
                )
                .shadow(color: Color.black.opacity(0.40), radius: 20, x: 0, y: 10)
            }
            .buttonStyle(.plain)
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .center)
        }
    }

    @ViewBuilder
    private func recommendationCover(for event: WebEvent) -> some View {
        if let cover = AppConfig.resolvedURLString(event.coverAssetURL),
        let url = URL(string: cover) {
            AsyncImage(url: url) { phase in
                switch phase {
                case .empty:
                    Color.black.opacity(0.72)
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                        .frame(maxWidth: .infinity, maxHeight: .infinity)  // ← 明确撑满父容器
                        .clipped()                                          // ← 在这里就裁剪，不依赖外层
                case .failure:
                    recommendationFallbackCover
                @unknown default:
                    recommendationFallbackCover
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)  // ← AsyncImage 本身也要约束
            .clipped()                                          // ← 双重保险
        } else {
            recommendationFallbackCover
        }
    }

    private var recommendationFallbackCover: some View {
        LinearGradient(
            colors: [
                Color(red: 0.08, green: 0.45, blue: 0.42),
                Color(red: 0.04, green: 0.12, blue: 0.16),
                Color.black
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    // MARK: - 大气覆盖层调整：让底部更暗，突出文字可读性

    private var recommendationAtmosphereOverlay: some View {
        ZStack {
            // 主渐变：顶部透明 → 底部深黑，加强底部文字对比
            LinearGradient(
                colors: [
                    Color.black.opacity(0.0),
                    Color.black.opacity(0.15),
                    Color.black.opacity(0.65),
                    Color.black.opacity(0.88)
                ],
                startPoint: .top,
                endPoint: .bottom
            )

            // 左上青色光晕（呼应参考图氛围）
            RadialGradient(
                colors: [
                    Color(red: 0.16, green: 0.95, blue: 0.92).opacity(0.28),
                    .clear
                ],
                center: .topLeading,
                startRadius: 10,
                endRadius: 280
            )
            .blendMode(.screen)
        }
    }

    private func recommendationHeadline(_ text: String) -> some View {
        let clean = text.trimmingCharacters(in: .whitespacesAndNewlines)
        let display = isChineseUI ? clean : clean.uppercased()

        return ViewThatFits(in: .vertical) {
            Text(display)
                .font(recommendHeadlineFont(size: 40, text: display).leading(.tight))
                .lineLimit(3)
                .minimumScaleFactor(0.34)
                .allowsTightening(true)
                .lineSpacing(-3)
                .tracking(isChineseUI ? 0.25 : 0.15)
            Text(display)
                .font(recommendHeadlineFont(size: 34, text: display).leading(.tight))
                .lineLimit(3)
                .minimumScaleFactor(0.34)
                .allowsTightening(true)
                .lineSpacing(-3)
                .tracking(isChineseUI ? 0.2 : 0.12)
            Text(display)
                .font(recommendHeadlineFont(size: 30, text: display).leading(.tight))
                .lineLimit(3)
                .minimumScaleFactor(0.34)
                .allowsTightening(true)
                .lineSpacing(-3)
                .tracking(isChineseUI ? 0.15 : 0.1)
            Text(display)
                .font(recommendHeadlineFont(size: 26, text: display).leading(.tight))
                .lineLimit(3)
                .minimumScaleFactor(0.34)
                .allowsTightening(true)
                .lineSpacing(-3)
                .tracking(isChineseUI ? 0.1 : 0.08)
            Text(display)
                .font(recommendHeadlineFont(size: 22, text: display).leading(.tight))
                .lineLimit(3)
                .minimumScaleFactor(0.34)
                .allowsTightening(true)
                .lineSpacing(-3)
                .tracking(isChineseUI ? 0.06 : 0.06)
        }
        .foregroundStyle(Color.white)
        .multilineTextAlignment(.leading)
        .frame(maxWidth: .infinity, alignment: .leading)
    }


    private var isChineseUI: Bool {
        switch AppLanguagePreference.current.effectiveLanguage {
        case .zh:
            return true
        case .en:
            return false
        case .system:
            let first = Locale.preferredLanguages.first?.lowercased() ?? ""
            return first.hasPrefix("zh")
        }
    }

    private func recommendHeadlineFont(size: CGFloat, text: String) -> Font {
        ensureRecommendFontRegistered()
        if UIFont(name: "AlteHaasGrotesk_Bold", size: size) != nil {
            return .custom("AlteHaasGrotesk_Bold", size: size)
        }
        return .custom(preferredFontName(candidates: ["Alte Haas Grotesk Bold", "Alte Haas Grotesk", "HelveticaNeue-Bold", "Arial-BoldMT", "AvenirNext-Bold"], fallback: "HelveticaNeue-Bold"), size: size)
    }

    private func recommendMetaFont(size: CGFloat, text: String? = nil) -> Font {
        ensureRecommendFontRegistered()
        if UIFont(name: "AlteHaasGrotesk_Bold", size: size) != nil {
            return .custom("AlteHaasGrotesk_Bold", size: size)
        }
        return .custom(preferredFontName(candidates: ["Alte Haas Grotesk Bold", "Alte Haas Grotesk", "HelveticaNeue-Bold", "Arial-BoldMT", "AvenirNext-Bold"], fallback: "HelveticaNeue-Bold"), size: size)
    }

    private func preferredFontName(candidates: [String], fallback: String) -> String {
        for candidate in candidates where UIFont(name: candidate, size: 15) != nil {
            return candidate
        }
        return fallback
    }

    private func ensureRecommendFontRegistered() {
        guard !Self.didRegisterAlteHaasFont else { return }
        guard let fontURL = Bundle.main.url(forResource: "altehaasgroteskbold", withExtension: "ttf") else { return }
        CTFontManagerRegisterFontsForURL(fontURL as CFURL, .process, nil)
        Self.didRegisterAlteHaasFont = true
    }

    private func logRecommendFontDiagnosticsIfNeeded() {
        guard !Self.didLogRecommendFontDiagnostics else { return }
        Self.didLogRecommendFontDiagnostics = true

        let englishHeadlineCandidates = ["AlteHaasGrotesk_Bold", "Alte Haas Grotesk Bold", "Alte Haas Grotesk", "HelveticaNeue-Bold", "Arial-BoldMT", "AvenirNext-Bold"]
        let englishMetaCandidates = ["AlteHaasGrotesk_Bold", "Alte Haas Grotesk Bold", "Alte Haas Grotesk", "HelveticaNeue-Bold", "Arial-BoldMT", "AvenirNext-Bold"]
        let chineseHeadlineCandidates = ["PingFangSC-Heavy", "STHeitiSC-Medium", "HiraginoSansGB-W6"]
        let chineseMetaCandidates = ["PingFangSC-Regular", "STHeitiSC-Light"]

        let resolvedEnglishHeadline = preferredFontName(candidates: englishHeadlineCandidates, fallback: "HelveticaNeue-Bold")
        let resolvedEnglishMeta = preferredFontName(candidates: englishMetaCandidates, fallback: "HelveticaNeue-Bold")
        let resolvedChineseHeadline = preferredFontName(candidates: chineseHeadlineCandidates, fallback: "PingFangSC-Heavy")
        let resolvedChineseMeta = preferredFontName(candidates: chineseMetaCandidates, fallback: "PingFangSC-Regular")

        let matchedAlteFonts = UIFont.familyNames
            .flatMap { family in UIFont.fontNames(forFamilyName: family) }
            .filter { $0.lowercased().contains("alte") }

        print("[RecommendFont] isChineseUI=\(isChineseUI) effectiveLanguage=\(AppLanguagePreference.current.effectiveLanguage.rawValue)")
        print("[RecommendFont] AlteHaasGrotesk_Bold available=\(UIFont(name: "AlteHaasGrotesk_Bold", size: 16) != nil)")
        print("[RecommendFont] resolvedEnglishHeadline=\(resolvedEnglishHeadline) resolvedEnglishMeta=\(resolvedEnglishMeta)")
        print("[RecommendFont] resolvedChineseHeadline=\(resolvedChineseHeadline) resolvedChineseMeta=\(resolvedChineseMeta)")
        print("[RecommendFont] loadedAlteFonts=\(matchedAlteFonts)")
    }

    private func recommendationPill(title: String, background: Color) -> some View {
        Text(title)
            .font(recommendMetaFont(size: 12))
            .lineLimit(1)
            .minimumScaleFactor(0.75)
            .fixedSize(horizontal: true, vertical: false)
            .foregroundStyle(Color.white)
            .padding(.horizontal, 10)
            .padding(.vertical, 5)
            .background(background, in: Capsule())
    }

    private func recommendationLocationText(for event: WebEvent) -> String {
        if !event.summaryLocation.isEmpty {
            return event.summaryLocation
        }
        if let venue = event.venueName, !venue.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return venue
        }
        return L("地点待定", "Location TBA")
    }

    private func recommendationDateText(for event: WebEvent) -> String {
        event.startDate.appLocalizedDateRangeText(to: event.endDate)
    }

    private func recommendationActionButtons(_ event: WebEvent) -> some View {
        recommendActionButton(
            title: L("收藏", "Save"),
            systemName: isMarked(event.id) ? "star.fill" : "star",
            background: isMarked(event.id) ? Color(red: 0.99, green: 0.82, blue: 0.22) : Color.black.opacity(0.45),
            foreground: .white
        ) {
            Task { await toggleMarked(event: event) }
        }
    }

    private func recommendActionButton(
        title: String,
        systemName: String,
        background: Color,
        foreground: Color,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            HStack(spacing: 6) {
                Image(systemName: systemName)
                    .font(.system(size: 13, weight: .semibold))
                Text(title)
                    .font(recommendMetaFont(size: 12))
            }
            .foregroundStyle(foreground)
            .padding(.horizontal, 12)
            .padding(.vertical, 9)
            .background(background, in: Capsule())
            .overlay(
                Capsule()
                    .stroke(Color.white.opacity(0.2), lineWidth: 1)
            )
        }
        .buttonStyle(.plain)
    }

    private func reload() async {
        await loadPersonalEventCheckins()
        await loadRecommendations()
    }

    private func loadRecommendations() async {
        guard !isLoading else { return }
        isLoading = true
        defer { isLoading = false }

        do {
            var uniqueByID: [String: WebEvent] = [:]
            var page = 1
            var totalPages = 1

            repeat {
                let result = try await service.fetchEvents(
                    page: page,
                    limit: 100,
                    search: nil,
                    eventType: nil,
                    status: "all"
                )
                for event in result.items {
                    uniqueByID[event.id] = event
                }
                totalPages = max(result.pagination?.totalPages ?? 1, 1)
                page += 1
            } while page <= totalPages

            let source = Array(uniqueByID.values).filter { event in
                EventVisualStatus.resolve(event: event) != .cancelled
            }

            events = Array(source.shuffled().prefix(10))
            let validIDs = Set(loopItems.map(\.id))
            if scrollPositionID == nil || !(scrollPositionID.map { validIDs.contains($0) } ?? false) {
                scrollPositionID = centerPageID(for: 0)
            }
        } catch {
            errorMessage = error.userFacingMessage
        }
    }

    private func loadPersonalEventCheckins() async {
        guard appState.session != nil else {
            markedCheckinIDsByEventID = [:]
            return
        }

        do {
            let page = try await service.fetchMyCheckins(page: 1, limit: 200, type: "event")
            let checkins = page.items.filter { ($0.type.lowercased() == "event") && $0.eventId != nil }
            var markedMap: [String: String] = [:]
            for item in checkins {
                guard let eventID = item.eventId else { continue }
                let note = item.note?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? ""
                if note == "marked" { markedMap[eventID] = item.id }
            }
            markedCheckinIDsByEventID = markedMap
        } catch {
            errorMessage = error.userFacingMessage
        }
    }

    @MainActor
    private func toggleMarked(event: WebEvent) async {
        guard appState.session != nil else {
            errorMessage = L("请先登录再收藏活动", "Please log in before saving events.")
            return
        }

        do {
            if let checkinID = markedCheckinIDsByEventID[event.id] {
                try await service.deleteCheckin(id: checkinID)
                markedCheckinIDsByEventID[event.id] = nil
            } else {
                let created = try await service.createCheckin(
                    input: CreateCheckinInput(type: "event", eventId: event.id, djId: nil, note: "marked", rating: nil)
                )
                markedCheckinIDsByEventID[event.id] = created.id
            }
        } catch {
            errorMessage = error.userFacingMessage
        }
    }

    private func isMarked(_ eventID: String) -> Bool {
        markedCheckinIDsByEventID[eventID] != nil
    }
}

private enum EventVisualStatus: String {
    case upcoming
    case ongoing
    case ended
    case cancelled

    var title: String {
        switch AppLanguagePreference.current.effectiveLanguage {
        case .zh:
            switch self {
            case .upcoming: return "即将开始"
            case .ongoing: return "进行中"
            case .ended: return "已结束"
            case .cancelled: return "已取消"
            }
        case .en, .system:
            switch self {
            case .upcoming: return "Upcoming"
            case .ongoing: return "Ongoing"
            case .ended: return "Ended"
            case .cancelled: return "Cancelled"
            }
        }
    }

    var apiValue: String { rawValue }

    var badgeBackground: Color {
        switch self {
        case .upcoming: return Color.orange.opacity(0.68)
        case .ongoing: return Color.green.opacity(0.68)
        case .ended: return Color.black.opacity(0.58)
        case .cancelled: return Color(red: 0.86, green: 0.20, blue: 0.28).opacity(0.66)
        }
    }

    var badgeBorder: Color {
        switch self {
        case .upcoming: return Color.orange.opacity(0.82)
        case .ongoing: return Color.green.opacity(0.84)
        case .ended: return Color.white.opacity(0.24)
        case .cancelled: return Color(red: 1.0, green: 0.45, blue: 0.50).opacity(0.9)
        }
    }

    static func resolve(startDate: Date, endDate: Date, fallbackStatus: String? = nil, now: Date = Date()) -> EventVisualStatus {
        if let fallback = from(raw: fallbackStatus), fallback == .cancelled {
            return .cancelled
        }
        guard endDate >= startDate else {
            return from(raw: fallbackStatus) ?? (now < startDate ? .upcoming : .ended)
        }
        if now < startDate { return .upcoming }
        if now > endDate { return .ended }
        return .ongoing
    }

    static func resolve(event: WebEvent, now: Date = Date()) -> EventVisualStatus {
        resolve(startDate: event.startDate, endDate: event.endDate, fallbackStatus: event.status, now: now)
    }

    static func from(raw value: String?) -> EventVisualStatus? {
        guard let value = value?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased(), !value.isEmpty else {
            return nil
        }
        switch value {
        case "upcoming":
            return .upcoming
        case "ongoing":
            return .ongoing
        case "ended":
            return .ended
        case "cancelled", "canceled":
            return .cancelled
        default:
            return nil
        }
    }
}

private struct OngoingStatusBars: View {
    var body: some View {
        TimelineView(.animation(minimumInterval: 0.12)) { timeline in
            let phase = timeline.date.timeIntervalSinceReferenceDate * 5.8

            HStack(alignment: .bottom, spacing: 2) {
                bar(height: animatedHeight(phase: phase))
                bar(height: animatedHeight(phase: phase + 0.8))
                bar(height: animatedHeight(phase: phase + 1.6))
            }
            .frame(height: 10)
        }
        .frame(width: 13, height: 10)
    }

    private func animatedHeight(phase: TimeInterval) -> CGFloat {
        let base: CGFloat = 3
        let amplitude: CGFloat = 6
        return base + abs(CGFloat(sin(phase))) * amplitude
    }

    private func bar(height: CGFloat) -> some View {
        Capsule()
            .fill(Color.white.opacity(0.98))
            .frame(width: 2.6, height: max(3, min(10, height)))
    }
}

private extension WebEvent {
    private var normalizedImageAssets: [WebEventImageAsset] {
        let assets = imageAssets ?? []
        return assets.sorted { lhs, rhs in
            let leftOrder = lhs.order ?? Int.max
            let rightOrder = rhs.order ?? Int.max
            if leftOrder != rightOrder { return leftOrder < rightOrder }
            let leftSort = lhs.sort ?? Int.max
            let rightSort = rhs.sort ?? Int.max
            if leftSort != rightSort { return leftSort < rightSort }
            return lhs.url < rhs.url
        }
    }

    private func normalizedAssetBucket(_ rawType: String?) -> String {
        let normalized = (rawType ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: "-", with: "")

        if normalized == "tt" || normalized.contains("timetable") {
            return "timetable"
        }
        if normalized == "luall" || normalized.contains("lineup") {
            return "lineup"
        }
        if normalized.contains("cover") || normalized.contains("poster") {
            return "cover"
        }
        return "other"
    }

    private func dedupedURLs(_ urls: [String]) -> [String] {
        var seen = Set<String>()
        var result: [String] = []
        for raw in urls {
            let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { continue }
            let key = trimmed.lowercased()
            guard !seen.contains(key) else { continue }
            seen.insert(key)
            result.append(trimmed)
        }
        return result
    }

    var lineupAssetURLs: [String] {
        let fromAssets = normalizedImageAssets
            .filter { normalizedAssetBucket($0.type) == "lineup" }
            .map(\.url)
        return dedupedURLs(fromAssets + [lineupImageUrl ?? ""])
    }

    var timetableAssetURLs: [String] {
        let fromAssets = normalizedImageAssets
            .filter { normalizedAssetBucket($0.type) == "timetable" }
            .map(\.url)
        return dedupedURLs(fromAssets)
    }

    var cardImageURL: String? {
        lineupAssetURLs.first ?? coverAssetURL
    }

    var coverAssetURL: String? {
        let fromAssets = normalizedImageAssets
            .first { normalizedAssetBucket($0.type) == "cover" }?
            .url
        let trimmedAsset = fromAssets?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmedAsset, !trimmedAsset.isEmpty {
            return trimmedAsset
        }
        let trimmedCover = coverImageUrl?.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmedCover?.isEmpty == false {
            return trimmedCover
        }
        // Fallback: when cover is missing, use lineup as detail hero background.
        return lineupAssetURLs.first
    }
}

private struct EventRow: View {
    let event: WebEvent
    private let coverWidth: CGFloat = 144
    private let coverHeight: CGFloat = 172
    private let actionColumnReserveWidth: CGFloat = 48

    var body: some View {
        let visualStatus = EventVisualStatus.resolve(event: event)
        let coverShape = RoundedRectangle(cornerRadius: 14, style: .continuous)

        HStack(alignment: .top, spacing: 12) {
            eventCoverLayer
            .frame(width: coverWidth, height: coverHeight)
            .clipShape(coverShape)
            .contentShape(coverShape) //加上这行看看会不会限制点击区域
            .overlay(alignment: .topLeading) {
                eventDateBadge
                    .padding(8)
            }
            .overlay(alignment: .bottomLeading) {
                eventStatusBadge(visualStatus)
                    .padding(8)
            }

            VStack(alignment: .leading, spacing: 7) {
                Text(event.name)
                    .font(.headline)
                    .foregroundStyle(RaverTheme.primaryText)
                    .lineLimit(2)
                VStack(alignment: .leading, spacing: 7) {
                    Text(EventTypeOption.displayText(for: event.eventType))
                        .font(.caption.weight(.medium))
                        .foregroundStyle(RaverTheme.accent)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(
                            Capsule()
                                .fill(RaverTheme.accent.opacity(0.15))
                        )

                    Label(eventDateRangeText, systemImage: "calendar")
                        .font(.caption)
                        .foregroundStyle(RaverTheme.secondaryText)

                    if let venue = event.venueName, !venue.isEmpty {
                        Label(venue, systemImage: "building.2")
                            .font(.caption)
                            .foregroundStyle(RaverTheme.secondaryText)
                            .lineLimit(2)
                            .truncationMode(.tail)
                            .multilineTextAlignment(.leading)
                    }

                    if !event.summaryLocation.isEmpty {
                        Label(event.summaryLocation, systemImage: "mappin.and.ellipse")
                            .font(.caption)
                            .foregroundStyle(RaverTheme.secondaryText)
                            .lineLimit(2)
                            .truncationMode(.tail)
                            .multilineTextAlignment(.leading)
                    }
                }
                .padding(.trailing, actionColumnReserveWidth)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
        }
        .frame(minHeight: coverHeight + 4, alignment: .topLeading)
        .padding(12)
        .background(
            RoundedRectangle(cornerRadius: 16, style: .continuous)
                .fill(RaverTheme.card)
        )
    }

    @ViewBuilder
    private var eventCoverLayer: some View {
        if let cover = AppConfig.resolvedURLString(event.cardImageURL),
           let url = URL(string: cover) {
            AsyncImage(url: url) { phase in
                switch phase {
                case .empty:
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .fill(RaverTheme.card)
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                case .failure:
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .fill(RaverTheme.card)
                @unknown default:
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .fill(RaverTheme.card)
                }
            }
        } else {
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [RaverTheme.accent.opacity(0.35), RaverTheme.card],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    Image(systemName: "ticket.fill")
                        .font(.title3)
                        .foregroundStyle(RaverTheme.secondaryText)
                )
        }
    }

    private var eventDateBadge: some View {
        VStack(spacing: 0) {
            Text(event.startDate.appLocalizedMonthBadgeText())
                .font(.system(size: 10, weight: .semibold))
                .foregroundStyle(RaverTheme.primaryText)
            Text("\(Calendar.current.component(.day, from: event.startDate))")
                .font(.system(size: 20, weight: .bold))
                .foregroundStyle(RaverTheme.primaryText)
        }
        .padding(.horizontal, 8)
        .padding(.vertical, 6)
        .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 9, style: .continuous))
    }

    private var eventDateRangeText: String {
        let calendar = Calendar.current
        let start = event.startDate
        let end = event.endDate

        if AppLanguagePreference.current.effectiveLanguage == .zh {
            return start.appLocalizedDateRangeText(to: end)
        }

        guard end >= start else {
            return Self.eventFullDateFormatter.string(from: start)
        }

        if calendar.isDate(start, inSameDayAs: end) {
            return Self.eventFullDateFormatter.string(from: start)
        }

        let startYear = calendar.component(.year, from: start)
        let endYear = calendar.component(.year, from: end)
        let startMonth = calendar.component(.month, from: start)
        let endMonth = calendar.component(.month, from: end)

        if startYear == endYear, startMonth == endMonth {
            let monthText = Self.eventMonthFormatter.string(from: start)
            let startDay = calendar.component(.day, from: start)
            let endDay = calendar.component(.day, from: end)
            return "\(monthText) \(startDay)-\(endDay), \(startYear)"
        }

        if startYear == endYear {
            let startText = Self.eventMonthDayFormatter.string(from: start)
            let endText = Self.eventMonthDayFormatter.string(from: end)
            return "\(startText)-\(endText), \(startYear)"
        }

        let startText = Self.eventFullDateFormatter.string(from: start)
        let endText = Self.eventFullDateFormatter.string(from: end)
        return "\(startText)-\(endText)"
    }

    private static let eventMonthFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "MMM"
        return formatter
    }()

    private static let eventMonthDayFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "MMM d"
        return formatter
    }()

    private static let eventFullDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "MMM d, yyyy"
        return formatter
    }()

    @ViewBuilder
    private func eventStatusBadge(_ status: EventVisualStatus) -> some View {
        HStack(spacing: 6) {
            if status == .ongoing {
                OngoingStatusBars()
            }
            Text(status.title)
                .font(.system(size: 11, weight: .semibold))
        }
        .foregroundStyle(.white)
        .padding(.horizontal, 9)
        .padding(.vertical, 5)
        .background(
            Capsule()
                .fill(status.badgeBackground)
        )
        .overlay(
            Capsule()
                .stroke(status.badgeBorder, lineWidth: 0.85)
        )
    }
}

private struct EventCalendarSheet: View {
    @Environment(\.dismiss) private var dismiss

    let events: [WebEvent]
    let markedEventIDs: Set<String>
    @Binding var selectedDate: Date
    @Binding var selectedFilters: Set<EventCalendarViewFilter>
    let onEventSelected: (WebEvent) -> Void

    @State private var displayedMonth: Date
    private let calendar = Calendar.current

    init(
        events: [WebEvent],
        markedEventIDs: Set<String>,
        selectedDate: Binding<Date>,
        selectedFilters: Binding<Set<EventCalendarViewFilter>>,
        onEventSelected: @escaping (WebEvent) -> Void
    ) {
        self.events = events
        self.markedEventIDs = markedEventIDs
        _selectedDate = selectedDate
        _selectedFilters = selectedFilters
        self.onEventSelected = onEventSelected
        _displayedMonth = State(initialValue: Calendar.current.startOfMonth(for: selectedDate.wrappedValue))
    }

    var body: some View {
        VStack(spacing: 14) {
            HStack {
                Text(LL("活动日历"))
                    .font(.title3.weight(.bold))
                    .foregroundStyle(RaverTheme.primaryText)
                Spacer()
                Button {
                    dismiss()
                } label: {
                    Image(systemName: "chevron.down")
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(RaverTheme.secondaryText)
                }
            }
            .padding(.horizontal, 16)
            .padding(.top, 12)

                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 8) {
                        ForEach(EventCalendarViewFilter.allCases) { filter in
                            Button {
                                toggleFilter(filter)
                            } label: {
                                HStack(spacing: 5) {
                                    Image(systemName: filter.icon)
                                        .font(.caption.weight(.semibold))
                                    Text(filter.title)
                                        .font(.caption.weight(.semibold))
                                }
                                .padding(.horizontal, 10)
                                .padding(.vertical, 7)
                                .background(
                                    Capsule()
                                        .fill(selectedFilters.contains(filter) ? RaverTheme.accent : RaverTheme.card)
                                )
                                .foregroundStyle(selectedFilters.contains(filter) ? Color.white : RaverTheme.secondaryText)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                    .padding(.horizontal, 16)
                }

                VStack(spacing: 10) {
                    HStack {
                        Button {
                            shiftMonth(by: -1)
                        } label: {
                            Image(systemName: "chevron.left")
                        }
                        .buttonStyle(.plain)
                        .foregroundStyle(RaverTheme.secondaryText)

                        Spacer()

                        Text(displayedMonth.appLocalizedYMText())
                            .font(.headline)
                            .foregroundStyle(RaverTheme.primaryText)

                        Spacer()

                        Button {
                            shiftMonth(by: 1)
                        } label: {
                            Image(systemName: "chevron.right")
                        }
                        .buttonStyle(.plain)
                        .foregroundStyle(RaverTheme.secondaryText)
                    }

                    let weekdays = calendar.shortStandaloneWeekdaySymbols
                    HStack(spacing: 0) {
                        ForEach(weekdays.indices, id: \.self) { idx in
                            Text(weekdays[idx])
                                .font(.caption2.weight(.semibold))
                                .foregroundStyle(RaverTheme.secondaryText)
                                .frame(maxWidth: .infinity)
                        }
                    }

                    LazyVGrid(columns: Array(repeating: GridItem(.flexible(), spacing: 2), count: 7), spacing: 8) {
                        ForEach(monthCells.indices, id: \.self) { idx in
                            if let date = monthCells[idx] {
                                Button {
                                    selectedDate = date
                                } label: {
                                    VStack(spacing: 4) {
                                        Text("\(calendar.component(.day, from: date))")
                                            .font(.subheadline.weight(calendar.isDate(date, inSameDayAs: selectedDate) ? .bold : .regular))
                                            .foregroundStyle(dayTextColor(for: date))

                                        HStack(spacing: 3) {
                                            ForEach(dayMarkerColors(for: date).indices, id: \.self) { markerIdx in
                                                Circle()
                                                    .fill(dayMarkerColors(for: date)[markerIdx])
                                                    .frame(width: 5, height: 5)
                                            }
                                        }
                                        .frame(height: 6)
                                    }
                                    .frame(maxWidth: .infinity, minHeight: 42)
                                    .padding(.vertical, 2)
                                    .background(dayBackground(for: date))
                                    .clipShape(RoundedRectangle(cornerRadius: 8, style: .continuous))
                                }
                                .buttonStyle(.plain)
                            } else {
                                Color.clear.frame(height: 42)
                            }
                        }
                    }
                }
                .padding(12)
                .background(RaverTheme.card)
                .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                .padding(.horizontal, 16)

                VStack(alignment: .leading, spacing: 10) {
                    HStack {
                        Text(selectedDate.appLocalizedYMDText())
                            .font(.headline)
                            .foregroundStyle(RaverTheme.primaryText)
                        Spacer()
                        Text(L("共 \(eventsOnSelectedDay.count) 场", "\(eventsOnSelectedDay.count) events"))
                            .font(.caption)
                            .foregroundStyle(RaverTheme.secondaryText)
                    }

                    if eventsOnSelectedDay.isEmpty {
                        ContentUnavailableView(LL("当日暂无活动"), systemImage: "calendar")
                    } else {
                        ScrollView {
                            LazyVStack(spacing: 10) {
                                ForEach(eventsOnSelectedDay) { event in
                                    Button {
                                        onEventSelected(event)
                                    } label: {
                                        HStack(alignment: .top, spacing: 10) {
                                            eventCoverImage(event)
                                                .frame(width: 80, height: 80)
                                                .clipShape(RoundedRectangle(cornerRadius: 10, style: .continuous))

                                            VStack(alignment: .leading, spacing: 4) {
                                                Text(event.name)
                                                    .font(.subheadline.weight(.semibold))
                                                    .foregroundStyle(RaverTheme.primaryText)
                                                    .lineLimit(2)
                                                Text(event.startDate.formatted(date: .omitted, time: .shortened))
                                                    .font(.caption)
                                                    .foregroundStyle(RaverTheme.secondaryText)
                                                if !event.summaryLocation.isEmpty {
                                                    Text(event.summaryLocation)
                                                        .font(.caption2)
                                                        .foregroundStyle(RaverTheme.secondaryText)
                                                }
                                            }
                                            .frame(maxWidth: .infinity, alignment: .leading)

                                            VStack(spacing: 4) {
                                                if markedEventIDs.contains(event.id) {
                                                    tag(L("标记", "Marked"), color: RaverTheme.accent)
                                                }
                                            }
                                        }
                                        .padding(10)
                                        .background(RaverTheme.card)
                                        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                                    }
                                    .buttonStyle(.plain)
                                }
                            }
                        }
                    }
                }
                .padding(.horizontal, 16)

                Spacer(minLength: 0)
            }
            .background(RaverTheme.background)
            .onChange(of: selectedDate) { _, newDate in
                let monthStart = calendar.startOfMonth(for: newDate)
                if !calendar.isDate(monthStart, equalTo: displayedMonth, toGranularity: .month) {
                    displayedMonth = monthStart
                }
            }
    }

    private var filteredEvents: [WebEvent] {
        let filters = selectedFilters.isEmpty ? Set([EventCalendarViewFilter.all]) : selectedFilters
        if filters.contains(.all) {
            return events.sorted(by: { $0.startDate < $1.startDate })
        }
        return events
            .filter { event in
                filters.contains(.marked) && markedEventIDs.contains(event.id)
            }
            .sorted(by: { $0.startDate < $1.startDate })
    }

    private var eventsOnSelectedDay: [WebEvent] {
        filteredEvents.filter { calendar.isDate($0.startDate, inSameDayAs: selectedDate) }
    }

    private var monthCells: [Date?] {
        guard let monthInterval = calendar.dateInterval(of: .month, for: displayedMonth),
              let dayRange = calendar.range(of: .day, in: .month, for: displayedMonth) else {
            return []
        }

        let firstWeekday = calendar.component(.weekday, from: monthInterval.start)
        let leading = (firstWeekday - calendar.firstWeekday + 7) % 7
        var cells: [Date?] = Array(repeating: nil, count: leading)

        for day in dayRange {
            if let date = calendar.date(byAdding: .day, value: day - 1, to: monthInterval.start) {
                cells.append(date)
            }
        }
        while cells.count % 7 != 0 {
            cells.append(nil)
        }
        return cells
    }

    private func dayMarkerColors(for date: Date) -> [Color] {
        let dayEvents = filteredEvents.filter { calendar.isDate($0.startDate, inSameDayAs: date) }
        guard !dayEvents.isEmpty else { return [] }
        let hasMarked = dayEvents.contains(where: { markedEventIDs.contains($0.id) })
        var markers: [Color] = []
        markers.append(RaverTheme.accent)
        if hasMarked { markers.append(Color.orange) }
        return Array(markers.prefix(3))
    }

    private func dayTextColor(for date: Date) -> Color {
        if calendar.isDate(date, inSameDayAs: selectedDate) {
            return .white
        }
        if calendar.isDate(date, inSameDayAs: Date()) {
            return RaverTheme.accent
        }
        return RaverTheme.primaryText
    }

    private func dayBackground(for date: Date) -> some ShapeStyle {
        if calendar.isDate(date, inSameDayAs: selectedDate) {
            return AnyShapeStyle(RaverTheme.accent)
        }
        return AnyShapeStyle(Color.clear)
    }

    private func tag(_ text: String, color: Color) -> some View {
        Text(text)
            .font(.caption2.weight(.bold))
            .foregroundStyle(.white)
            .padding(.horizontal, 6)
            .padding(.vertical, 3)
            .background(Capsule().fill(color))
    }

    private func toggleFilter(_ filter: EventCalendarViewFilter) {
        if selectedFilters.contains(filter) {
            selectedFilters.remove(filter)
            if selectedFilters.isEmpty {
                selectedFilters = [.all]
            }
            return
        }
        selectedFilters.insert(filter)
    }

    private func shiftMonth(by delta: Int) {
        if let date = calendar.date(byAdding: .month, value: delta, to: displayedMonth) {
            displayedMonth = calendar.startOfMonth(for: date)
        }
    }

    @ViewBuilder
    private func eventCoverImage(_ event: WebEvent) -> some View {
        if let cover = AppConfig.resolvedURLString(event.cardImageURL), let url = URL(string: cover) {
            AsyncImage(url: url) { phase in
                switch phase {
                case .empty:
                    eventFallbackCover
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                case .failure:
                    eventFallbackCover
                @unknown default:
                    eventFallbackCover
                }
            }
        } else {
            eventFallbackCover
        }
    }

    private var eventFallbackCover: some View {
        ZStack {
            LinearGradient(
                colors: [RaverTheme.accent.opacity(0.35), RaverTheme.card],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            Image(systemName: "calendar")
                .font(.title2)
                .foregroundStyle(RaverTheme.secondaryText)
        }
    }
}

private enum EventLineupActType: String, CaseIterable, Hashable, Codable, Identifiable {
    case solo
    case b2b
    case b3b

    var id: String { rawValue }

    var title: String {
        switch self {
        case .solo: return "Solo"
        case .b2b: return "B2B"
        case .b3b: return "B3B"
        }
    }

    var performerCount: Int {
        switch self {
        case .solo: return 1
        case .b2b: return 2
        case .b3b: return 3
        }
    }

    var separator: String {
        switch self {
        case .solo: return ""
        case .b2b: return " B2B "
        case .b3b: return " B3B "
        }
    }
}

private struct EventLineupPerformer: Identifiable, Hashable {
    var id: String
    var name: String
    var djID: String?
    var avatarUrl: String?
}

private struct EventLineupResolvedAct: Hashable {
    var type: EventLineupActType
    var performers: [EventLineupPerformer]

    var displayName: String {
        EventLineupActCodec.composeName(type: type, performerNames: performers.map(\.name))
    }

    var isCollaborative: Bool {
        type != .solo
    }
}

private enum EventLineupActCodec {
    static func parse(slot: WebEventLineupSlot) -> EventLineupResolvedAct {
        let preferredName = slot.djName.trimmingCharacters(in: .whitespacesAndNewlines)
        let fallbackName = slot.dj?.name.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let rawName = preferredName.isEmpty ? fallbackName : preferredName
        return parse(
            name: rawName,
            djID: slot.dj?.id ?? slot.djId,
            avatarUrl: slot.dj?.avatarUrl,
            performerIDPrefix: "slot-\(slot.id)-p"
        )
    }

    static func parse(
        name: String,
        djID: String? = nil,
        avatarUrl: String? = nil,
        performerIDPrefix: String = "performer"
    ) -> EventLineupResolvedAct {
        let trimmedName = name.trimmingCharacters(in: .whitespacesAndNewlines)

        if let parts = split(trimmedName, keyword: "B3B"), parts.count >= 3 {
            var performers = parts.enumerated().map { index, item in
                EventLineupPerformer(
                    id: "\(performerIDPrefix)-\(index)",
                    name: item,
                    djID: nil,
                    avatarUrl: nil
                )
            }
            if let normalized = normalizedID(djID), !performers.isEmpty {
                performers[0].djID = normalized
                performers[0].avatarUrl = avatarUrl
            }
            return EventLineupResolvedAct(type: .b3b, performers: performers)
        }

        if let parts = split(trimmedName, keyword: "B2B"), parts.count >= 2 {
            var performers = parts.enumerated().map { index, item in
                EventLineupPerformer(
                    id: "\(performerIDPrefix)-\(index)",
                    name: item,
                    djID: nil,
                    avatarUrl: nil
                )
            }
            if let normalized = normalizedID(djID), !performers.isEmpty {
                performers[0].djID = normalized
                performers[0].avatarUrl = avatarUrl
            }
            return EventLineupResolvedAct(type: .b2b, performers: performers)
        }

        return EventLineupResolvedAct(
            type: .solo,
            performers: [
                EventLineupPerformer(
                    id: "\(performerIDPrefix)-0",
                    name: trimmedName,
                    djID: normalizedID(djID),
                    avatarUrl: avatarUrl
                )
            ]
        )
    }

    static func composeName(type: EventLineupActType, performerNames: [String]) -> String {
        let normalized = performerNames
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }

        guard !normalized.isEmpty else { return "" }
        switch type {
        case .solo:
            return normalized[0]
        case .b2b:
            return normalized.prefix(2).joined(separator: EventLineupActType.b2b.separator)
        case .b3b:
            return normalized.prefix(3).joined(separator: EventLineupActType.b3b.separator)
        }
    }

    static func normalizePerformers(
        _ performers: [EventLineupPerformer],
        type: EventLineupActType,
        prefix: String
    ) -> [EventLineupPerformer] {
        let expectedCount = type.performerCount
        var normalized = Array(performers.prefix(expectedCount))
        while normalized.count < expectedCount {
            normalized.append(
                EventLineupPerformer(
                    id: "\(prefix)-\(normalized.count)",
                    name: "",
                    djID: nil,
                    avatarUrl: nil
                )
            )
        }
        for index in normalized.indices {
            normalized[index].id = "\(prefix)-\(index)"
            if type != .solo {
                normalized[index].djID = nil
                normalized[index].avatarUrl = nil
            }
        }
        return normalized
    }

    static func canonicalKey(for act: EventLineupResolvedAct) -> String {
        let names = act.performers
            .map { $0.name.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() }
            .filter { !$0.isEmpty }
            .joined(separator: "|")
        return "\(act.type.rawValue)-\(names)"
    }

    private static func split(_ raw: String, keyword: String) -> [String]? {
        guard !raw.isEmpty else { return nil }
        let token = "__EVENT_LINEUP_SPLIT_TOKEN__"
        let pattern = "(?i)\\s*\(keyword)\\s*"
        let replaced = raw.replacingOccurrences(
            of: pattern,
            with: token,
            options: .regularExpression
        )
        let pieces = replaced
            .components(separatedBy: token)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        return pieces.count > 1 ? pieces : nil
    }

    private static func normalizedID(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }
}

private func normalizedDJLookupKey(_ raw: String) -> String {
    raw
        .trimmingCharacters(in: .whitespacesAndNewlines)
        .folding(options: [.diacriticInsensitive, .caseInsensitive], locale: .current)
}

private func fetchExactDJMatches(
    names: [String],
    service: any WebFeatureService
) async -> [String: WebDJ] {
    var resolved: [String: WebDJ] = [:]
    var queue: [String] = []

    for name in names {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { continue }
        let key = normalizedDJLookupKey(trimmed)
        guard resolved[key] == nil, !queue.contains(where: { normalizedDJLookupKey($0) == key }) else { continue }
        queue.append(trimmed)
    }

    for name in queue {
        if Task.isCancelled { break }
        do {
            let page = try await service.fetchDJs(page: 1, limit: 20, search: name, sortBy: "name")
            if Task.isCancelled { break }
            let key = normalizedDJLookupKey(name)
            if let exact = page.items.first(where: { normalizedDJLookupKey($0.name) == key }) {
                resolved[key] = exact
                continue
            }
            if let aliasMatched = page.items.first(where: { dj in
                (dj.aliases ?? []).contains { normalizedDJLookupKey($0) == key }
            }) {
                resolved[key] = aliasMatched
            }
        } catch {
            continue
        }
    }

    return resolved
}

private enum EventWeekScheduleMode {
    static let marker = "[[raver_schedule_mode:week]]"
    static let editorDaysPerWeek = 4

    static func isEnabled(in rawDescription: String?) -> Bool {
        guard let rawDescription else { return false }
        return rawDescription.contains(marker)
    }

    static func stripMarker(from rawDescription: String?) -> String {
        guard let rawDescription else { return "" }
        return rawDescription
            .replacingOccurrences(of: marker, with: "")
            .replacingOccurrences(of: #"\n{3,}"#, with: "\n\n", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    static func embedMarker(into userDescription: String, enabled: Bool) -> String? {
        let cleaned = stripMarker(from: userDescription)
        guard enabled else { return cleaned.nilIfEmpty }
        if cleaned.isEmpty {
            return marker
        }
        return "\(cleaned)\n\n\(marker)"
    }

    static func weekDayIndex(for date: Date, anchorDate: Date) -> (week: Int, day: Int)? {
        let calendar = Calendar.current
        let anchorDay = calendar.startOfDay(for: anchorDate)
        let targetDay = calendar.startOfDay(for: date)
        let offset = calendar.dateComponents([.day], from: anchorDay, to: targetDay).day ?? 0
        guard offset >= 0 else { return nil }
        return (week: offset / 7 + 1, day: offset % 7 + 1)
    }

    static func weekDayTitle(week: Int, day: Int) -> String {
        "Week\(week)·Day\(day)"
    }
}

private struct EventCheckinDayOption: Identifiable, Hashable {
    let id: String
    let dayIndex: Int
    let dayDate: Date
    let attendedAt: Date
    let weekIndex: Int?
    let dayInWeek: Int?

    var usesWeekLabel: Bool {
        weekIndex != nil && dayInWeek != nil
    }

    var title: String {
        if let weekIndex, let dayInWeek {
            return EventWeekScheduleMode.weekDayTitle(week: weekIndex, day: dayInWeek)
        }
        return "Day\(dayIndex)"
    }
    var subtitle: String { dayDate.appLocalizedYMDText() }
}

private struct EventCheckinDJOption: Identifiable, Hashable {
    let id: String
    let djID: String
    let name: String
    let avatarUrl: String?
    let actType: EventLineupActType
    let performers: [EventLineupPerformer]
}

private struct EventCheckinSelectionSheet: View {
    @Environment(\.dismiss) private var dismiss

    let eventName: String
    let options: [EventCheckinDayOption]
    let djOptionsByDayID: [String: [EventCheckinDJOption]]
    let initialSelectedDayIDs: Set<String>
    let initialSelectedDJIDsByDayID: [String: Set<String>]
    let confirmButtonTitle: String
    let destructiveButtonTitle: String?
    let onDelete: (() -> Void)?
    let onConfirm: ([String: Set<String>]) -> Void

    @State private var selectedDayIDs: Set<String>
    @State private var selectedDJIDsByDayID: [String: Set<String>]
    @State private var expandedDayIDs: Set<String>

    private var columns: [GridItem] {
        [
            GridItem(.flexible(minimum: 0), spacing: 10),
            GridItem(.flexible(minimum: 0), spacing: 10),
            GridItem(.flexible(minimum: 0), spacing: 10),
            GridItem(.flexible(minimum: 0), spacing: 10)
        ]
    }

    private var b2bColumns: [GridItem] {
        [
            GridItem(.flexible(minimum: 0), spacing: 10),
            GridItem(.flexible(minimum: 0), spacing: 10)
        ]
    }

    private var dayUnitLabel: String {
        options.contains(where: \.usesWeekLabel) ? L("Week/Day", "Week/Day") : L("Day", "Day")
    }

    init(
        eventName: String,
        options: [EventCheckinDayOption],
        djOptionsByDayID: [String: [EventCheckinDJOption]],
        initialSelectedDayIDs: Set<String> = [],
        initialSelectedDJIDsByDayID: [String: Set<String>] = [:],
        confirmButtonTitle: String = "",
        destructiveButtonTitle: String? = nil,
        onDelete: (() -> Void)? = nil,
        onConfirm: @escaping ([String: Set<String>]) -> Void
    ) {
        self.eventName = eventName
        self.options = options
        self.djOptionsByDayID = djOptionsByDayID
        self.initialSelectedDayIDs = initialSelectedDayIDs
        self.initialSelectedDJIDsByDayID = initialSelectedDJIDsByDayID
        self.confirmButtonTitle = confirmButtonTitle.isEmpty ? L("确认打卡", "Confirm Check-in") : confirmButtonTitle
        self.destructiveButtonTitle = destructiveButtonTitle
        self.onDelete = onDelete
        self.onConfirm = onConfirm
        _selectedDayIDs = State(initialValue: initialSelectedDayIDs)
        _selectedDJIDsByDayID = State(initialValue: initialSelectedDJIDsByDayID)
        _expandedDayIDs = State(initialValue: initialSelectedDayIDs)
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 14) {
                    Text(eventName)
                        .font(.headline.weight(.bold))
                        .foregroundStyle(RaverTheme.primaryText)
                        .lineLimit(2)

                    Text(L("勾选参加的\(dayUnitLabel)，展开后直接选择当天看过的 DJ", "Select attended \(dayUnitLabel), then expand to choose DJs you watched that day."))
                        .font(.subheadline)
                        .foregroundStyle(RaverTheme.secondaryText)

                    if !selectedDayIDs.isEmpty {
                        Text(L("已选 \(selectedDayIDs.count) 天 · \(selectedDJCount) 个演出", "Selected \(selectedDayIDs.count) days · \(selectedDJCount) acts"))
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Color(red: 0.82, green: 0.39, blue: 0.20))
                            .padding(.horizontal, 10)
                            .padding(.vertical, 5)
                            .background(Color(red: 1.00, green: 0.94, blue: 0.90), in: Capsule())
                    }

                    VStack(spacing: 12) {
                        ForEach(options) { option in
                            daySelectionCard(option)
                        }
                    }
                }
                .padding(.horizontal, 16)
                .padding(.vertical, 14)
            }
            .navigationTitle(L("活动打卡", "Event Check-in"))
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button(L("取消", "Cancel")) { dismiss() }
                }
                if let destructiveButtonTitle, let onDelete {
                    ToolbarItem(placement: .bottomBar) {
                        Button(destructiveButtonTitle, role: .destructive) {
                            onDelete()
                            dismiss()
                        }
                    }
                }
                ToolbarItem(placement: .confirmationAction) {
                    Button(confirmButtonTitle) {
                        onConfirm(normalizedSelections())
                        dismiss()
                    }
                    .disabled(selectedDayIDs.isEmpty)
                }
            }
            .onAppear {
                applyInitialSelections()
            }
        }
    }

    private var selectedDJCount: Int {
        normalizedSelections().values.reduce(0) { $0 + $1.count }
    }

    private func daySelectionCard(_ option: EventCheckinDayOption) -> some View {
        let isSelected = selectedDayIDs.contains(option.id)
        let isExpanded = expandedDayIDs.contains(option.id)
        let djOptions = djOptionsByDayID[option.id] ?? []
        let selectedDJIDs = selectedDJIDsByDayID[option.id] ?? []

        return VStack(alignment: .leading, spacing: 12) {
            HStack(spacing: 12) {
                Button {
                    toggleDaySelection(option.id)
                } label: {
                    Image(systemName: isSelected ? "checkmark.square.fill" : "square")
                        .font(.title3)
                        .foregroundStyle(isSelected ? RaverTheme.accent : RaverTheme.secondaryText)
                }
                .buttonStyle(.plain)

                Button {
                    toggleDayExpansion(option.id)
                } label: {
                    HStack(spacing: 12) {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(option.title)
                                .font(.headline)
                                .foregroundStyle(RaverTheme.primaryText)
                            Text(option.subtitle)
                                .font(.caption)
                                .foregroundStyle(RaverTheme.secondaryText)
                        }

                        Spacer(minLength: 8)

                        if isSelected || !selectedDJIDs.isEmpty {
                            Text(L("\(selectedDJIDs.count) 个演出", "\(selectedDJIDs.count) acts"))
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(RaverTheme.accent)
                        }

                        Image(systemName: isExpanded ? "chevron.up" : "chevron.down")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(RaverTheme.secondaryText)
                    }
                }
                .buttonStyle(.plain)
            }

            if isExpanded {
                if djOptions.isEmpty {
                    Text(L("这一天暂未配置可选 DJ，确认后会只记录该\(dayUnitLabel)的活动打卡。", "No DJ options are configured for this day. Confirming will record only this \(dayUnitLabel) event check-in."))
                        .font(.caption)
                        .foregroundStyle(RaverTheme.secondaryText)
                        .padding(.leading, 2)
                } else {
                    let grouped = groupedCheckinOptions(djOptions)

                    VStack(alignment: .leading, spacing: 12) {
                        if !grouped.b3b.isEmpty {
                            VStack(alignment: .leading, spacing: 8) {
                                Text("B3B")
                                    .font(.caption2.weight(.semibold))
                                    .foregroundStyle(RaverTheme.secondaryText)
                                ForEach(grouped.b3b) { dj in
                                    checkinDJOptionButton(
                                        dj,
                                        dayID: option.id,
                                        selectedDJIDs: selectedDJIDs,
                                        avatarSize: .large
                                    )
                                }
                            }
                        }

                        if !grouped.b2b.isEmpty {
                            VStack(alignment: .leading, spacing: 8) {
                                Text("B2B")
                                    .font(.caption2.weight(.semibold))
                                    .foregroundStyle(RaverTheme.secondaryText)
                                LazyVGrid(columns: b2bColumns, alignment: .leading, spacing: 12) {
                                    ForEach(grouped.b2b) { dj in
                                        checkinDJOptionButton(
                                            dj,
                                            dayID: option.id,
                                            selectedDJIDs: selectedDJIDs,
                                            avatarSize: .medium
                                        )
                                    }
                                }
                            }
                        }

                        if !grouped.others.isEmpty {
                            VStack(alignment: .leading, spacing: 8) {
                                if !grouped.b2b.isEmpty || !grouped.b3b.isEmpty {
                                    Text(LL("其他演出"))
                                        .font(.caption2.weight(.semibold))
                                        .foregroundStyle(RaverTheme.secondaryText)
                                }
                                LazyVGrid(columns: columns, alignment: .leading, spacing: 12) {
                                    ForEach(grouped.others) { dj in
                                        checkinDJOptionButton(
                                            dj,
                                            dayID: option.id,
                                            selectedDJIDs: selectedDJIDs,
                                            avatarSize: .small
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
        .padding(14)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(RaverTheme.card, in: RoundedRectangle(cornerRadius: 18, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 18, style: .continuous)
                .stroke(isSelected ? RaverTheme.accent.opacity(0.4) : Color.white.opacity(0.06), lineWidth: 1)
        )
    }

    private func toggleDaySelection(_ dayID: String) {
        if selectedDayIDs.contains(dayID) {
            selectedDayIDs.remove(dayID)
            selectedDJIDsByDayID[dayID] = nil
            expandedDayIDs.remove(dayID)
        } else {
            selectedDayIDs.insert(dayID)
            selectedDJIDsByDayID[dayID] = selectedDJIDsByDayID[dayID] ?? []
            expandedDayIDs.insert(dayID)
        }
    }

    private func toggleDayExpansion(_ dayID: String) {
        if expandedDayIDs.contains(dayID) {
            expandedDayIDs.remove(dayID)
        } else {
            selectedDJIDsByDayID[dayID] = selectedDJIDsByDayID[dayID] ?? []
            expandedDayIDs.insert(dayID)
        }
    }

    private func toggleDJSelection(dayID: String, djID: String) {
        if !selectedDayIDs.contains(dayID) {
            selectedDayIDs.insert(dayID)
        }
        var selected = selectedDJIDsByDayID[dayID] ?? []
        if selected.contains(djID) {
            selected.remove(djID)
        } else {
            selected.insert(djID)
        }
        selectedDJIDsByDayID[dayID] = selected
    }

    private func applyInitialSelections() {
        selectedDayIDs = initialSelectedDayIDs
        selectedDJIDsByDayID = initialSelectedDJIDsByDayID
        expandedDayIDs = initialSelectedDayIDs
    }

    private func normalizedSelections() -> [String: Set<String>] {
        var normalized: [String: Set<String>] = [:]
        for dayID in selectedDayIDs {
            normalized[dayID] = selectedDJIDsByDayID[dayID] ?? []
        }
        return normalized
    }

    private enum CheckinAvatarSize {
        case small
        case medium
        case large

        var frameWidth: CGFloat {
            switch self {
            case .small: return 56
            case .medium: return 132
            case .large: return 206
            }
        }

        var frameHeight: CGFloat {
            56
        }
    }

    private func groupedCheckinOptions(_ options: [EventCheckinDJOption]) -> (b3b: [EventCheckinDJOption], b2b: [EventCheckinDJOption], others: [EventCheckinDJOption]) {
        (
            b3b: options.filter { $0.actType == .b3b },
            b2b: options.filter { $0.actType == .b2b },
            others: options.filter { $0.actType != .b3b && $0.actType != .b2b }
        )
    }

    private func checkinDJOptionButton(
        _ option: EventCheckinDJOption,
        dayID: String,
        selectedDJIDs: Set<String>,
        avatarSize: CheckinAvatarSize
    ) -> some View {
        let djIsSelected = selectedDJIDs.contains(option.djID)

        return Button {
            toggleDJSelection(dayID: dayID, djID: option.djID)
        } label: {
            VStack(spacing: 7) {
                djAvatar(option, size: avatarSize)
                    .frame(width: avatarSize.frameWidth, height: avatarSize.frameHeight)
                    .shadow(
                        color: djIsSelected ? RaverTheme.accent.opacity(0.92) : .clear,
                        radius: djIsSelected ? 14 : 0,
                        x: 0,
                        y: djIsSelected ? 1 : 0
                    )
                    .shadow(
                        color: djIsSelected ? Color.black.opacity(0.28) : .clear,
                        radius: djIsSelected ? 6 : 0,
                        x: 0,
                        y: djIsSelected ? 3 : 0
                    )

                Text(option.name)
                    .font(.system(size: 11, weight: .semibold))
                    .foregroundStyle(RaverTheme.primaryText)
                    .lineLimit(3)
                    .multilineTextAlignment(.center)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
            .padding(.vertical, 4)
        }
        .buttonStyle(.plain)
    }

    private func performerAvatar(_ performer: EventLineupPerformer?, fallbackName: String, size: CGFloat) -> some View {
        let performerName = performer?.name.trimmingCharacters(in: .whitespacesAndNewlines) ?? fallbackName
        return Group {
            if let avatar = AppConfig.resolvedDJAvatarURLString(performer?.avatarUrl, size: .small),
               let url = URL(string: avatar) {
                AsyncImage(url: url) { phase in
                    switch phase {
                    case .empty:
                        Circle().fill(RaverTheme.card)
                    case .success(let image):
                        image.resizable().scaledToFill()
                    case .failure:
                        Circle().fill(RaverTheme.card)
                    @unknown default:
                        Circle().fill(RaverTheme.card)
                    }
                }
            } else {
                Circle()
                    .fill(RaverTheme.card)
                    .overlay(
                        Text(String((performerName.isEmpty ? "?" : performerName).prefix(1)).uppercased())
                            .font(.system(size: max(9, size * 0.33), weight: .bold))
                            .foregroundStyle(RaverTheme.secondaryText)
                    )
            }
        }
        .frame(width: size, height: size)
        .clipShape(Circle())
    }

    private func actConnectorLabel(text: String, color: Color, vertical: Bool) -> some View {
        Text("B")
            .font(.system(size: vertical ? 8.5 : 7.5, weight: .bold, design: .rounded))
            .foregroundStyle(color)
            .frame(width: vertical ? 10 : 12, height: vertical ? 10 : 12)
            .background(color.opacity(0.14), in: Circle())
            .scaleEffect(vertical ? 1.2 : 1.12)
            .frame(width: vertical ? 10 : 16, height: vertical ? 24 : 14)
    }

    @ViewBuilder
    private func djAvatar(_ option: EventCheckinDJOption, size: CheckinAvatarSize) -> some View {
        if option.actType == .solo {
            performerAvatar(option.performers.first, fallbackName: option.name, size: min(size.frameWidth, size.frameHeight))
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        } else {
            let performers = Array(option.performers.prefix(option.actType.performerCount))
            let b2bColor = Color(red: 0.98, green: 0.52, blue: 0.20)
            let b3bColor = Color(red: 0.18, green: 0.74, blue: 0.92)
            let avatarSize = min(size.frameWidth, size.frameHeight)

            HStack(spacing: 10) {
                ForEach(Array(performers.enumerated()), id: \.offset) { index, performer in
                    performerAvatar(performer, fallbackName: performer.name, size: avatarSize)
                    if index < performers.count - 1 {
                        actConnectorLabel(
                            text: option.actType == .b2b ? "B2B" : "B3B",
                            color: option.actType == .b2b ? b2bColor : b3bColor,
                            vertical: true
                        )
                    }
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .center)
        }
    }
}

private enum DJCheckinSubmission {
    case eventBinding(eventID: String, attendedAt: Date)
    case manual(eventName: String, attendedAt: Date)
}

private struct DJCheckinEventBindingOption: Identifiable, Hashable {
    let id: String
    let name: String
    let city: String?
    let country: String?
    let attendedAt: Date?
    let startDate: Date?
}

private struct DJCheckinBindingSheet: View {
    private enum Mode: String, CaseIterable, Identifiable {
        case bindEvent
        case manual

        var id: String { rawValue }
        var title: String {
            switch self {
            case .bindEvent: return L("绑定活动", "Bind Event")
            case .manual: return L("手动填写", "Manual Input")
            }
        }
    }

    @Environment(\.dismiss) private var dismiss
    private let service = AppEnvironment.makeWebService()

    let djName: String
    let onConfirm: (DJCheckinSubmission) -> Void

    @State private var mode: Mode = .bindEvent
    @State private var eventSearchText = ""
    @State private var historyOptions: [DJCheckinEventBindingOption] = []
    @State private var remoteOptions: [DJCheckinEventBindingOption] = []
    @State private var selectedEventID: String?
    @State private var manualEventName = ""
    @State private var manualAttendedAt = Date()
    @State private var isLoadingHistory = false
    @State private var isSearchingEvents = false
    @State private var searchTask: Task<Void, Never>?

    var body: some View {
        NavigationStack {
            Form {
                Section {
                    Picker(LL("打卡方式"), selection: $mode) {
                        ForEach(Mode.allCases) { item in
                            Text(item.title).tag(item)
                        }
                    }
                    .pickerStyle(.segmented)
                }

                if mode == .bindEvent {
                    Section(LL("绑定到活动（优先）")) {
                        TextField(L("搜索活动名称", "Search event name"), text: $eventSearchText)
                            .textInputAutocapitalization(.never)
                            .autocorrectionDisabled(true)

                        if isLoadingHistory && historyOptions.isEmpty {
                            ProgressView(LL("读取你的活动历史..."))
                        }

                        if !filteredHistoryOptions.isEmpty {
                            Text(LL("我的活动历史"))
                                .font(.caption)
                                .foregroundStyle(RaverTheme.secondaryText)

                            ForEach(filteredHistoryOptions) { option in
                                eventOptionRow(option)
                            }
                        }

                        if !eventSearchKeyword.isEmpty {
                            Text(LL("搜索结果"))
                                .font(.caption)
                                .foregroundStyle(RaverTheme.secondaryText)

                            if isSearchingEvents {
                                ProgressView(LL("搜索活动中..."))
                            } else if remoteOptions.isEmpty {
                                Text(LL("没有更多匹配活动"))
                                    .font(.caption)
                                    .foregroundStyle(RaverTheme.secondaryText)
                            } else {
                                ForEach(remoteOptions) { option in
                                    eventOptionRow(option)
                                }
                            }
                        }

                        if let selectedOption {
                            Text(L("将自动按活动时间记录打卡：\(autoAttendedAt(for: selectedOption).appLocalizedYMDHMText())", "Check-in time will follow event schedule automatically: \(autoAttendedAt(for: selectedOption).appLocalizedYMDHMText())"))
                                .font(.caption)
                                .foregroundStyle(RaverTheme.secondaryText)
                        } else {
                            Text(LL("请在搜索或历史中选择一场活动。"))
                                .font(.caption)
                                .foregroundStyle(RaverTheme.secondaryText)
                        }
                    }
                } else {
                    Section(LL("手动填写")) {
                        TextField(LL("活动名称"), text: $manualEventName)
                        DatePicker(
                            L("观演时间", "Attended Time"),
                            selection: $manualAttendedAt,
                            in: ...Date(),
                            displayedComponents: [.date, .hourAndMinute]
                        )
                    }
                }
            }
            .navigationTitle(L("\(djName) 打卡", "\(djName) Check-in"))
            .navigationBarTitleDisplayMode(.inline)
            .task {
                await loadHistory()
            }
            .onChange(of: eventSearchText) { _, _ in
                guard mode == .bindEvent else { return }
                searchTask?.cancel()
                searchTask = Task {
                    try? await Task.sleep(nanoseconds: 280_000_000)
                    guard !Task.isCancelled else { return }
                    await searchEvents()
                }
            }
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button(L("取消", "Cancel")) { dismiss() }
                }
                ToolbarItem(placement: .confirmationAction) {
                    Button(L("确认打卡", "Confirm Check-in")) {
                        switch mode {
                        case .bindEvent:
                            guard let selectedOption else { return }
                            onConfirm(
                                .eventBinding(
                                    eventID: selectedOption.id,
                                    attendedAt: autoAttendedAt(for: selectedOption)
                                )
                            )
                        case .manual:
                            let trimmed = manualEventName.trimmingCharacters(in: .whitespacesAndNewlines)
                            guard !trimmed.isEmpty else { return }
                            onConfirm(.manual(eventName: trimmed, attendedAt: manualAttendedAt))
                        }
                        dismiss()
                    }
                    .disabled(!canConfirm)
                }
            }
        }
    }

    @ViewBuilder
    private func eventOptionRow(_ option: DJCheckinEventBindingOption) -> some View {
        Button {
            selectedEventID = option.id
        } label: {
            HStack(spacing: 10) {
                VStack(alignment: .leading, spacing: 4) {
                    Text(option.name)
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(RaverTheme.primaryText)
                        .lineLimit(1)

                    Text(eventOptionSubtitle(option))
                        .font(.caption)
                        .foregroundStyle(RaverTheme.secondaryText)
                        .lineLimit(1)
                }
                Spacer()
                if selectedEventID == option.id {
                    Image(systemName: "checkmark.circle.fill")
                        .foregroundStyle(RaverTheme.accent)
                }
            }
        }
        .buttonStyle(.plain)
    }

    private var canConfirm: Bool {
        switch mode {
        case .bindEvent:
            return selectedOption != nil
        case .manual:
            return !manualEventName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        }
    }

    private var eventSearchKeyword: String {
        eventSearchText.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var filteredHistoryOptions: [DJCheckinEventBindingOption] {
        guard !eventSearchKeyword.isEmpty else { return historyOptions }
        let keyword = eventSearchKeyword.lowercased()
        return historyOptions.filter { option in
            option.name.lowercased().contains(keyword)
                || (option.city?.lowercased().contains(keyword) ?? false)
                || (option.country?.lowercased().contains(keyword) ?? false)
        }
    }

    private var selectedOption: DJCheckinEventBindingOption? {
        guard let selectedEventID else { return nil }
        return (historyOptions + remoteOptions).first(where: { $0.id == selectedEventID })
    }

    private func autoAttendedAt(for option: DJCheckinEventBindingOption) -> Date {
        if let attendedAt = option.attendedAt {
            return min(attendedAt, Date())
        }
        if let startDate = option.startDate {
            return min(startDate, Date())
        }
        return Date()
    }

    private func eventOptionSubtitle(_ option: DJCheckinEventBindingOption) -> String {
        let location = [option.city, option.country]
            .compactMap { value in
                guard let value, !value.isEmpty else { return nil }
                return value
            }
            .joined(separator: " · ")

        if let attendedAt = option.attendedAt {
            let attendedText = attendedAt.appLocalizedYMDHMText()
            return location.isEmpty
                ? L("我参加于 \(attendedText)", "I attended at \(attendedText)")
                : L("\(location) · 我参加于 \(attendedText)", "\(location) · I attended at \(attendedText)")
        }

        if let startDate = option.startDate {
            let startText = startDate.appLocalizedYMDHMText()
            return location.isEmpty
                ? L("开始于 \(startText)", "Starts at \(startText)")
                : L("\(location) · 开始于 \(startText)", "\(location) · Starts at \(startText)")
        }

        return location.isEmpty ? L("活动信息", "Event info") : location
    }

    private func loadHistory() async {
        guard !isLoadingHistory else { return }
        isLoadingHistory = true
        defer { isLoadingHistory = false }

        do {
            let page = try await service.fetchMyCheckins(page: 1, limit: 200, type: nil)
            var latestByEventID: [String: DJCheckinEventBindingOption] = [:]

            for item in page.items {
                guard let event = item.event else { continue }
                let candidate = DJCheckinEventBindingOption(
                    id: event.id,
                    name: event.name,
                    city: event.city,
                    country: event.country,
                    attendedAt: item.attendedAt,
                    startDate: event.startDate
                )

                if let existing = latestByEventID[event.id] {
                    if item.attendedAt > (existing.attendedAt ?? .distantPast) {
                        latestByEventID[event.id] = candidate
                    }
                } else {
                    latestByEventID[event.id] = candidate
                }
            }

            historyOptions = latestByEventID.values.sorted {
                ($0.attendedAt ?? $0.startDate ?? .distantPast) > ($1.attendedAt ?? $1.startDate ?? .distantPast)
            }

            if selectedEventID == nil {
                selectedEventID = historyOptions.first?.id
            }
        } catch {
            // Keep sheet usable even if history loading fails.
            historyOptions = []
        }
    }

    private func searchEvents() async {
        let keyword = eventSearchKeyword
        guard !keyword.isEmpty else {
            remoteOptions = []
            isSearchingEvents = false
            return
        }

        isSearchingEvents = true
        defer { isSearchingEvents = false }

        do {
            let page = try await service.fetchEvents(
                page: 1,
                limit: 20,
                search: keyword,
                eventType: nil,
                status: "all"
            )

            if Task.isCancelled || keyword != eventSearchKeyword {
                return
            }

            let historyIDs = Set(historyOptions.map(\.id))
            remoteOptions = page.items
                .filter { !historyIDs.contains($0.id) }
                .map {
                    DJCheckinEventBindingOption(
                        id: $0.id,
                        name: $0.name,
                        city: $0.city,
                        country: $0.country,
                        attendedAt: nil,
                        startDate: $0.startDate
                    )
                }
        } catch {
            if keyword == eventSearchKeyword {
                remoteOptions = []
            }
        }
    }
}

private struct EventDetailTabFramePreferenceKey: PreferenceKey {
    static var defaultValue: [EventDetailView.EventDetailTab: CGRect] = [:]

    static func reduce(value: inout [EventDetailView.EventDetailTab: CGRect], nextValue: () -> [EventDetailView.EventDetailTab: CGRect]) {
        value.merge(nextValue(), uniquingKeysWith: { _, new in new })
    }
}

private struct EventDetailPageOffsetPreferenceKey: PreferenceKey {
    static var defaultValue: [EventDetailView.EventDetailTab: CGFloat] = [:]

    static func reduce(value: inout [EventDetailView.EventDetailTab: CGFloat], nextValue: () -> [EventDetailView.EventDetailTab: CGFloat]) {
        value.merge(nextValue(), uniquingKeysWith: { _, new in new })
    }
}

