private struct EventRoutePlannerView: View {
    let event: WebEvent
    let days: [EventScheduleDay]
    let initialDayID: String

    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var appState: AppState

    @State private var selectedDayID: String
    @State private var selectedSlotIDs: Set<String> = []
    @State private var isGeneratingShare = false
    @State private var shareImage: UIImage?
    @State private var showShareSheet = false
    @State private var feedbackMessage: String?
    @State private var coverImage: UIImage?

    init(event: WebEvent, days: [EventScheduleDay], initialDayID: String) {
        self.event = event
        self.days = days
        self.initialDayID = initialDayID
        _selectedDayID = State(initialValue: initialDayID)
    }

    private var selectedDay: EventScheduleDay? {
        days.first(where: { $0.id == selectedDayID }) ?? days.first
    }

    private var displayNameForShare: String {
        let trimmed = appState.session?.user.displayName.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !trimmed.isEmpty { return trimmed }
        return appState.session?.user.username ?? "Raver"
    }

    var body: some View {
        NavigationView {
            ZStack {
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.06, blue: 0.11),
                        Color(red: 0.03, green: 0.03, blue: 0.04)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
                .ignoresSafeArea()

                ScrollView(showsIndicators: false) {
                    VStack(alignment: .leading, spacing: 14) {
                        if days.count > 1 {
                            daySelector
                        }

                        if let selectedDay {
                            EventTimelineBoardView(
                                event: event,
                                day: selectedDay,
                                selectedSlotIDs: selectedSlotIDs,
                                selectable: true,
                                onToggleSlot: { slot in
                                    if selectedSlotIDs.contains(slot.id) {
                                        selectedSlotIDs.remove(slot.id)
                                    } else {
                                        selectedSlotIDs.insert(slot.id)
                                    }
                                }
                            )
                            .frame(height: EventTimelineLayout.estimatedHeight(for: selectedDay.slots))
                        } else {
                            ContentUnavailableView(LL("等待时间表发布"), systemImage: "calendar.badge.exclamationmark")
                        }
                    }
                    .padding(.horizontal, 10)
                    .padding(.top, 12)
                    .padding(.bottom, 24)
                }
            }
            .navigationTitle(LL("定制路线"))
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button {
                        dismiss()
                    } label: {
                        Image(systemName: "chevron.left")
                            .font(.system(size: 14, weight: .semibold))
                    }
                }
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await exportSharePoster() }
                    } label: {
                        Image(systemName: "square.and.arrow.up")
                    }
                    .disabled(isGeneratingShare)
                    .opacity(isGeneratingShare ? 0.6 : 1)
                }
            }
            .onAppear {
                if selectedDayID.isEmpty {
                    selectedDayID = days.first?.id ?? ""
                }
            }
            .task {
                await loadCoverImageIfNeeded()
            }
            .sheet(isPresented: $showShareSheet) {
                if let shareImage {
                    ActivityShareSheet(items: [shareImage], completion: nil)
                }
            }
            .alert(L("提示", "Notice"), isPresented: Binding(
                get: { feedbackMessage != nil },
                set: { if !$0 { feedbackMessage = nil } }
            )) {
                Button(L("确定", "OK"), role: .cancel) {}
            } message: {
                Text(feedbackMessage ?? "")
            }
        }
    }

    private var daySelector: some View {
        //HorizontalAxisLockedScrollView(showsIndicators: false) {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 10) {
                ForEach(days) { day in
                    let selected = day.id == selectedDayID
                    Button {
                        selectedDayID = day.id
                    } label: {
                        Text(day.subtitle)
                            .font(EventScheduleTypography.semibold(15))
                            .foregroundStyle(selected ? Color.black.opacity(0.85) : Color.white.opacity(0.88))
                            .padding(.horizontal, 12)
                            .padding(.vertical, 7)
                            .background(
                                Capsule()
                                    .fill(selected ? Color.white.opacity(0.92) : Color.white.opacity(0.13))
                            )
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 2)
        }
    }

    @MainActor
    private func exportSharePoster() async {
        guard !isGeneratingShare else { return }
        guard let selectedDay else {
            feedbackMessage = L("暂无可分享的时间表", "No timetable available to share.")
            return
        }

        isGeneratingShare = true
        defer { isGeneratingShare = false }

        let stageCount = EventTimelineLayout.stageCount(for: selectedDay.slots)
        let stageRegionWidth =
            CGFloat(stageCount) * EventTimelineLayout.minStageWidth +
            CGFloat(max(stageCount - 1, 0)) * EventTimelineLayout.stageGap
        let boardWidth = EventTimelineLayout.axisWidth + stageRegionWidth
        let horizontalPadding: CGFloat = 72
        let posterWidth = max(1080, boardWidth + horizontalPadding)
        let boardHeight = EventTimelineLayout.estimatedHeight(for: selectedDay.slots)
        let posterHeight = max(1920, boardHeight + 280)

        let poster = EventRouteSharePosterView(
            event: event,
            day: selectedDay,
            selectedSlotIDs: selectedSlotIDs,
            username: displayNameForShare,
            coverImage: coverImage
        )
        .frame(width: posterWidth, height: posterHeight)

        let renderer = ImageRenderer(content: poster)
        renderer.scale = UIScreen.main.scale

        guard let image = renderer.uiImage else {
            feedbackMessage = L("行程图生成失败，请重试", "Failed to generate route image. Please try again.")
            return
        }

        shareImage = image
        showShareSheet = true
        await savePosterToPhotos(image)
    }

    @MainActor
    private func savePosterToPhotos(_ image: UIImage) async {
        let status = await PHPhotoLibrary.requestAuthorization(for: .addOnly)
        guard status == .authorized || status == .limited else {
            feedbackMessage = L("未获得相册权限，可先通过分享面板手动保存", "Photo permission denied. You can save manually from the share panel.")
            return
        }

        await withCheckedContinuation { continuation in
            PHPhotoLibrary.shared().performChanges({
                PHAssetChangeRequest.creationRequestForAsset(from: image)
            }) { success, error in
                DispatchQueue.main.async {
                    if success {
                        feedbackMessage = L("已保存到相册", "Saved to Photos.")
                    } else if let error {
                        feedbackMessage = L("保存失败：\(error.userFacingMessage ?? "")", "Save failed: \(error.userFacingMessage ?? "")")
                    } else {
                        feedbackMessage = L("保存失败，请重试", "Save failed. Please try again.")
                    }
                    continuation.resume()
                }
            }
        }
    }

    @MainActor
    private func loadCoverImageIfNeeded() async {
        guard coverImage == nil,
              let urlString = AppConfig.resolvedURLString(event.coverImageUrl),
              let url = URL(string: urlString) else {
            return
        }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            if let image = UIImage(data: data) {
                coverImage = image
            }
        } catch {
            // Keep gradient fallback for poster background.
        }
    }
}

private struct EventRoutineView: View {
    enum PresentationStyle {
        case pushed
        case embedded
    }

    let event: WebEvent
    let scheduledSlots: [WebEventLineupSlot]
    var presentationStyle: PresentationStyle = .pushed

    @State private var selectedDayID: String = ""
    @State private var showRoutePlanner = false

    private var isEmbedded: Bool {
        presentationStyle == .embedded
    }

    private var days: [EventScheduleDay] {
        EventScheduleDay.build(
            from: scheduledSlots,
            anchorDate: event.startDate,
            useWeekMode: EventWeekScheduleMode.isEnabled(in: event.description),
            dayRolloverHour: event.dayRolloverHour
        )
    }

    private var selectedDay: EventScheduleDay? {
        days.first(where: { $0.id == selectedDayID }) ?? days.first
    }

    var body: some View {
        Group {
            if days.isEmpty {
                ContentUnavailableView(LL("等待时间表发布"), systemImage: "calendar.badge.exclamationmark")
                    .frame(maxWidth: .infinity)
                    .padding(.vertical, 10)
            } else if isEmbedded {
                embeddedContent
            } else {
                standaloneContent
            }
        }
        .onAppear {
            if selectedDayID.isEmpty {
                selectedDayID = days.first?.id ?? ""
            }
        }
        .fullScreenCover(isPresented: $showRoutePlanner) {
            EventRoutePlannerView(
                event: event,
                days: days,
                initialDayID: selectedDayID
            )
        }
    }

    private var embeddedContent: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack {
                Spacer()
                Button(LL("定制路线")) {
                    showRoutePlanner = true
                }
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(RaverTheme.accent)
            }

            if days.count > 1 {
                daySelector
            }

            timelineBoard
        }
    }

    private var standaloneContent: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 14) {
                if days.count > 1 {
                    daySelector
                }

                timelineBoard
            }
            .padding(.horizontal, 10)
            .padding(.top, 12)
            .padding(.bottom, 24)
        }
        .background(
            LinearGradient(
                colors: [
                    Color(red: 0.05, green: 0.06, blue: 0.11),
                    RaverTheme.background
                ],
                startPoint: .top,
                endPoint: .bottom
            )
        )
        .navigationTitle(L("活动日程", "Event Schedule"))
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .topBarTrailing) {
                Button(L("定制路线", "Custom Route")) {
                    showRoutePlanner = true
                }
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(RaverTheme.accent)
            }
        }
    }

    @ViewBuilder
    private var timelineBoard: some View {
        if let selectedDay {
            EventTimelineBoardView(
                event: event,
                day: selectedDay,
                selectedSlotIDs: [],
                selectable: false,
                onToggleSlot: nil
            )
            .frame(height: EventTimelineLayout.estimatedHeight(for: selectedDay.slots))
        } else {
            ContentUnavailableView(LL("等待时间表发布"), systemImage: "calendar.badge.exclamationmark")
        }
    }

    private var daySelector: some View {
        //HorizontalAxisLockedScrollView(showsIndicators: false) {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 10) {
                ForEach(Array(days.enumerated()), id: \.offset) { _, day in
                    let selected = day.id == selectedDayID
                    Button {
                        selectedDayID = day.id
                    } label: {
                        Text(day.subtitle)
                            .font(EventScheduleTypography.semibold(15))
                            .foregroundStyle(selected ? Color.black.opacity(0.85) : Color.white.opacity(0.88))
                            .padding(.horizontal, 12)
                            .padding(.vertical, 7)
                            .background(
                                Capsule()
                                    .fill(selected ? Color.white.opacity(0.92) : Color.white.opacity(0.13))
                            )
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 2)
        }
    }
}

struct EventEditorView: View {
    enum Mode {
        case create
        case edit(WebEvent)

        var title: String {
            switch self {
            case .create: return L("发布活动", "Create Event")
            case .edit: return L("编辑活动", "Edit Event")
            }
        }
    }

    private static let eventTypeOptionKeys = EventTypeOption.allCases.map(\.rawValue)
    private static func normalizedStartOfDay(_ date: Date) -> Date {
        Calendar.current.startOfDay(for: date)
    }

    private static func normalizedEndOfDay(_ date: Date) -> Date {
        let calendar = Calendar.current
        let start = calendar.startOfDay(for: date)
        return calendar.date(byAdding: DateComponents(day: 1, second: -1), to: start) ?? start
    }

    private struct EditableLineupPerformer: Identifiable, Hashable {
        let id: UUID
        var djId: String?
        var djName: String

        init(id: UUID = UUID(), djId: String? = nil, djName: String = "") {
            self.id = id
            self.djId = djId
            self.djName = djName
        }
    }

    private struct EditableLineupSlot: Identifiable, Hashable {
        let id: UUID
        var actType: EventLineupActType
        var performers: [EditableLineupPerformer]
        var stageName: String
        var dayID: String?
        var startTime: Date?
        var endTime: Date?
        var isEditing: Bool

        init(
            id: UUID = UUID(),
            actType: EventLineupActType = .solo,
            performers: [EditableLineupPerformer],
            stageName: String = "",
            dayID: String? = nil,
            startTime: Date? = nil,
            endTime: Date? = nil,
            isEditing: Bool = false
        ) {
            self.id = id
            self.actType = actType
            self.performers = performers
            self.stageName = stageName
            self.dayID = dayID
            self.startTime = startTime
            self.endTime = endTime
            self.isEditing = isEditing
        }

        var displayName: String {
            EventLineupActCodec.composeName(type: actType, performerNames: performers.map(\.djName))
        }
    }

    private struct EditorDayOption: Identifiable, Hashable {
        let id: String
        let dayIndex: Int
        let date: Date
        let weekIndex: Int?
        let dayInWeek: Int?

        var title: String { "Day\(dayIndex)" }

        var weekDayTitle: String {
            if let weekIndex, let dayInWeek {
                return EventWeekScheduleMode.weekDayTitle(week: weekIndex, day: dayInWeek)
            }
            return title
        }
    }

    private struct LineupTimeDraft: Hashable {
        var startText: String
        var endText: String
        var durationText: String
        var endNextDay: Bool
    }

    private enum LineupTimeApplySource {
        case startOrEndText
        case durationText
        case endDayToggle
    }

    private struct TicketTierDraft: Identifiable, Hashable {
        let id: UUID
        var name: String
        var price: String
        var currency: String

        init(id: UUID = UUID(), name: String = "", price: String = "", currency: String = "CNY") {
            self.id = id
            self.name = name
            self.price = price
            self.currency = currency
        }
    }

    @Environment(\.dismiss) private var dismiss
    private let service = AppEnvironment.makeWebService()

    let mode: Mode
    let onSaved: () -> Void

    @State private var name = ""
    @State private var description = ""
    @State private var eventType = ""
    @State private var city = ""
    @State private var country = ""
    @State private var venueName = ""
    @State private var venueAddress = ""
    @State private var ticketUrl = ""
    @State private var officialWebsite = ""
    @State private var ticketCurrency = "CNY"
    @State private var ticketNotes = ""
    @State private var ticketTierDrafts: [TicketTierDraft] = []
    @State private var pickedLatitude: Double?
    @State private var pickedLongitude: Double?
    @State private var pickedMapAddress = ""
    @State private var showLocationPicker = false
    @State private var startDate = EventEditorView.normalizedStartOfDay(Date())
    @State private var endDate = EventEditorView.normalizedStartOfDay(Date())
