                                            .font(.caption)
                                            .foregroundStyle(RaverTheme.primaryText)
                                            .lineLimit(1)
                                        Spacer(minLength: 0)
                                        Button {
                                            boundDjIDs.removeAll { $0 == id }
                                        } label: {
                                            Image(systemName: "xmark.circle.fill")
                                                .foregroundStyle(RaverTheme.secondaryText)
                                        }
                                        .buttonStyle(.plain)
                                    }
