                                .autocorrectionDisabled()
                            Button(LL("搜索")) {
                                Task { await searchBindingBrands() }
                            }
                            .buttonStyle(.bordered)
                            .disabled(brandSearchText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || isSearchingBrands)
