            .navigationTitle(LL("编辑 DJ"))
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button(L("关闭", "Close")) {
                        showDJEditSheet = false
                    }
                    .disabled(isSavingDJProfile)
                }
            }
            .scrollDismissesKeyboard(.interactively)
