                    .foregroundStyle(.yellow)
                Text(LL("当前仅支持原生直连媒体地址（mp4/mov/webm/m3u8）。"))
                    .font(.caption)
                    .foregroundStyle(RaverTheme.secondaryText)
            }
            .padding(12)
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .leading)
            .background(Color.black)
