            if let total = labelsPagination?.total {
                Text(L("筛选后 \(labels.count) / 共 \(total) 个厂牌", "Filtered \(labels.count) / Total \(total) labels"))
                    .font(.caption)
                    .foregroundStyle(RaverTheme.secondaryText)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
        }
