    private var upcomingRelatedEvents: [WebEvent] {
        relatedEvents
            .filter {
                let status = EventVisualStatus.resolve(event: $0)
                return status != .ended && status != .cancelled
            }
            .sorted(by: { $0.startDate < $1.startDate })
    }

    private var endedRelatedEvents: [WebEvent] {
        relatedEvents
            .filter {
                let status = EventVisualStatus.resolve(event: $0)
                return status == .ended || status == .cancelled
            }
            .sorted(by: { $0.startDate > $1.startDate })
    }

